// Core fishing logic
const { FISH_TYPES, FISH_RARITIES, ROD_UPGRADES, FISHING_BAITS, FISHING_BOOSTERS } = require('./constants');
const logger = require('../../logger');

function getCatchOdds({ rodLevel, bait, boosters, luckBooster, activeBait, activeBooster }) {
  // Base odds from rarity
  const odds = Object.fromEntries(Object.keys(FISH_RARITIES).map(rarity => [rarity, FISH_RARITIES[rarity].chance]));

  // Apply rod upgrades
  if (rodLevel && rodLevel > 1) {
    const rod = ROD_UPGRADES.find(r => r.level === rodLevel);
    if (rod && rod.oddsBoost) {
      odds.RARE += rod.oddsBoost * 100;
      odds.EPIC += rod.oddsBoost * 100;
      odds.LEGENDARY += rod.oddsBoost * 50;
      odds.MYTHIC += rod.oddsBoost * 20;
      odds.COMMON -= rod.oddsBoost * 100;
    }
  }

  // Apply active bait effects
  if (activeBait) {
    const bait = FISHING_BAITS.find(b => b.id === activeBait);
    if (bait && bait.effects) {
      Object.entries(bait.effects).forEach(([rarity, boost]) => {
        if (odds[rarity] !== undefined) {
          odds[rarity] += boost * 100;
          // Reduce common fish chance to compensate
          odds.COMMON = Math.max(0, odds.COMMON - boost * 50);
        }
      });
    }
  }

  // Apply active booster effects
  if (activeBooster) {
    const booster = FISHING_BOOSTERS.find(b => b.id === activeBooster);
    if (booster && booster.effects) {
      if (booster.effects.luckBoost) {
        odds.RARE += booster.effects.luckBoost * 100;
        odds.EPIC += booster.effects.luckBoost * 50;
        odds.LEGENDARY += booster.effects.luckBoost * 25;
        odds.MYTHIC += booster.effects.luckBoost * 10;
        odds.COMMON = Math.max(0, odds.COMMON - booster.effects.luckBoost * 100);
      }
    }
  }

  // Apply legacy luckBooster (for backward compatibility)
  if (luckBooster) {
    odds.RARE += 2;
    odds.EPIC += 1;
    odds.LEGENDARY += 0.5;
    odds.MYTHIC += 0.2;
    odds.COMMON -= 3.7;
  }

  // Normalize odds
  const total = Object.values(odds).reduce((a, b) => a + b, 0);
  Object.keys(odds).forEach(k => odds[k] = Math.max(0, odds[k] * 100 / total));
  return odds;
}

function pickRarity(odds) {
  // 20% chance to catch nothing (reduced from 35% for better user experience)
  if (secureRandomFloat() < 0.20) return 'NOTHING';
  // Otherwise, pick based on odds (which should sum to 80)
  let roll = secureRandomFloat() * 80;
  let acc = 0;
  for (const [rarity, chance] of Object.entries(odds)) {
    acc += chance;
    if (roll < acc) return rarity;
  }
  return 'COMMON'; // fallback
}

function performFishing({ rodLevel, bait, boosters, luckBooster, multiCatch = 1, activeBait, activeBooster }) {
  try {
    const odds = getCatchOdds({ rodLevel, bait, boosters, luckBooster, activeBait, activeBooster });
    const results = [];

    // Determine multi-catch amount
    let actualMultiCatch = multiCatch;
    if (activeBooster) {
      const booster = FISHING_BOOSTERS.find(b => b.id === activeBooster);
      if (booster && booster.effects.multiCatch) {
        actualMultiCatch = Math.max(actualMultiCatch, booster.effects.multiCatch);
      }
    }

    for (let i = 0; i < actualMultiCatch; i++) {
      const rarity = pickRarity(odds);
      if (rarity === 'NOTHING') {
        results.push({ type: 'nothing' });
        continue;
      }
      const fishPool = FISH_TYPES.filter(f => f.rarity === rarity);
      const fish = secureRandomChoice(fishPool);
      results.push({ type: 'fish', fish });
    }

    return results;
  } catch (error) {
    logger.error('Error in performFishing:', error);
    return [{ type: 'error', error: error.message }];
  }
}

function pickFish(fishPool) {
  return secureRandomChoice(fishPool);
}

module.exports = { getCatchOdds, performFishing, pickRarity, pickFish };

// Fishing rewards logic
const { FISH_RARITIES, FISHING_BOOSTERS } = require('./constants');
const { secureRandomFloat } = require('../../utils/secureRandom');

function calculateFishValue(fish, { boosters, marketBonus = 1, activeBooster, globalMultiplier = 1 }) {
  let value = fish.basePrice;

  // Apply legacy boosters (for backward compatibility)
  if (boosters && boosters.valueBoost) {
    value *= (1 + boosters.valueBoost);
  }

  // Apply new booster system effects
  if (activeBooster) {
    const booster = FISHING_BOOSTERS.find(b => b.id === activeBooster);
    if (booster && booster.effects.valueBoost) {
      value *= (1 + booster.effects.valueBoost);
    }
  }

  // Apply market bonus
  value *= marketBonus;

  // Apply global multiplier
  value *= globalMultiplier;

  return Math.round(value);
}

function getCollectionReward(rarity) {
  // Example: reward coins for completing a rarity set
  const base = { COMMON: 2000, UNCOMMON: 5000, RARE: 15000, EPIC: 40000, LEGENDARY: 100000, MYTHIC: 500000 };
  return { coins: base[rarity] || 1000 };
}

function getRandomItemReward(rarity) {
  // Example: rare chance for special item
  if (rarity === 'MYTHIC') return { item: 'Mythic Relic', amount: 1 };
  if (rarity === 'LEGENDARY' && secureRandomFloat() < 0.1) return { item: 'Golden Bait', amount: 1 };
  if (rarity === 'EPIC' && secureRandomFloat() < 0.05) return { item: 'Epic Bait', amount: 1 };
  return null;
}

module.exports = { calculateFishValue, getCollectionReward, getRandomItemReward };

