          .addStringOption(opt => opt.setName('duration').setDescription('Duration (e.g. 1h 30m 10s, 90m, 3600s)').setRequired(true))
          .addNumberOption(opt => opt.setName('multiplier').setDescription('Reward multiplier (e.g. 2 for 2x, 4 for 4x)').setRequired(true))
      )
      .addSubcommand(sub =>
        sub.setName('stop')
          .setDescription('Stop the current party event')
      ),
    execute: withSafeReply(async (interaction) => {
      const ownerId = require('../../utils/utils').constants.OWNER_ID;
      if (!isSafeDiscordId(interaction.user.id)) {
        return reply(interaction, 'Invalid user ID.', { isUserBlacklisted, rateLimiter: rateLimiter(interaction.user.id) });
      }
      if (interaction.user.id !== ownerId) {
        logger.warn(`Unauthorized party command attempt by ${interaction.user.id}`);
        return reply(interaction, 'Only the bot owner can use this command.', { isUserBlacklisted, rateLimiter: rateLimiter(interaction.user.id) });
      }

      const sub = interaction.options.getSubcommand();
      const client = interaction.client;

      const announce = msg => {
        client.guilds.cache.forEach(async guild => {
          let channel = guild.systemChannel || guild.channels.cache.find(c => c.isTextBased && c.permissionsFor(guild.members.me).has('SendMessages'));
          if (channel) {
            try { 
              await channel.send(msg);
            } catch (e) { 
              logger.warn('Failed to send message to channel:', e);
            } 
          }
        });
      };

      if (sub === 'start') {
        const durationStr = interaction.options.getString('duration');
        const multiplier = interaction.options.getNumber('multiplier');

        // Input validation
        if (!durationStr || typeof durationStr !== 'string') {
          return reply(interaction, 'Please provide a valid duration.', { isUserBlacklisted, rateLimiter: rateLimiter(interaction.user.id) });
        }

        if (!multiplier || multiplier < 1 || multiplier > 10) {
          return reply(interaction, 'Multiplier must be between 1 and 10.', { isUserBlacklisted, rateLimiter: rateLimiter(interaction.user.id) });
        }

        // Parse duration
        const durationMs = parseDuration(durationStr);
        if (!durationMs) {
          return reply(interaction, 'Invalid duration format. Use: 1h 30m 10s, 90m, 3600s, etc.', { isUserBlacklisted, rateLimiter: rateLimiter(interaction.user.id) });
        }

        if (durationMs < 60000 || durationMs > 3600000) {
          return reply(interaction, 'Duration must be between 1 minute and 1 hour.', { isUserBlacklisted, rateLimiter: rateLimiter(interaction.user.id) });
        }

        // Set global party event
        try {
          global.partyEvent = {
            multiplier: multiplier,
            endTime: Date.now() + durationMs,
            startedBy: interaction.user.id
          };
        } catch (err) {
          logger.error('Error setting global party event:', err);
          return reply(interaction, 'Failed to start party event due to internal error.', { isUserBlacklisted, rateLimiter: rateLimiter(interaction.user.id) });
        }

        const embed = new EmbedBuilder()
          .setTitle('🎉 PARTY EVENT STARTED! 🎉')
          .setDescription(`**${multiplier}x** multiplier active for **${formatDuration(durationMs)}**!\n\nAll coin rewards are now multiplied by ${multiplier}!`)
          .setColor(0x00ff00)
          .setTimestamp();

        announce({ embeds: [embed] });

        // Auto-stop after duration
        setTimeout(() => {
          if (global.partyEvent && global.partyEvent.endTime <= Date.now()) {
            global.partyEvent = null;
            announce('🎊 **PARTY EVENT ENDED!** 🎊\nThe multiplier has returned to normal.');
          }
        }, durationMs);

        return reply(interaction, `Party event started! ${multiplier}x multiplier for ${formatDuration(durationMs)}.`, { isUserBlacklisted, rateLimiter: rateLimiter(interaction.user.id) });
      } else if (sub === 'stop') {
        if (!global.partyEvent) {
          return reply(interaction, 'No party event is currently active.', { isUserBlacklisted, rateLimiter: rateLimiter(interaction.user.id) });
        }

        global.partyEvent = null;
        announce('🎊 **PARTY EVENT ENDED!** 🎊\nThe multiplier has returned to normal.');
        return reply(interaction, 'Party event stopped.', { isUserBlacklisted, rateLimiter: rateLimiter(interaction.user.id) });
      }
    }, { isUserBlacklisted, rateLimiter: rateLimiter })
  }
];

// Helper function for parsing duration
function parseDuration(str) {
  const match = str.match(/^(\d+)([smhd])$/);
  if (!match) return null;

  const value = parseInt(match[1]);
  const unit = match[2];

  const multipliers = {
    s: 1000,
    m: 60 * 1000,
    h: 60 * 60 * 1000,
    d: 24 * 60 * 60 * 1000
  };

  return value * (multipliers[unit] || 0);
}

// Helper function for formatting duration
function formatDuration(ms) {
  if (typeof ms !== 'number' || ms < 0) return '0s';

  const seconds = Math.floor(ms / 1000);
  const minutes = Math.floor(seconds / 60);
  const hours = Math.floor(minutes / 60);
  const days = Math.floor(hours / 24);

  if (days > 0) return `${days}d ${hours % 24}h ${minutes % 60}m`;
  if (hours > 0) return `${hours}h ${minutes % 60}m`;
  if (minutes > 0) return `${minutes}m ${seconds % 60}s`;
    return `${seconds}s`;
}

