          .setDescription(`${winnerUser} defeated ${loserUser} in battle!`)
          .addFields(
            { name: '🎯 Power Levels', value: `${interaction.user.username}: ${userPower}\n${opponent.username}: ${oppPower}`, inline: true },
            { name: '🎲 Battle Rolls', value: `${interaction.user.username}: ${userRoll}\n${opponent.username}: ${oppRoll}`, inline: true },
            { name: '💰 Reward', value: `${winnerUser.username} won ${reward} Kelocoins!`, inline: true }
          )
          .setColor('#ff6b6b')
          .setTimestamp();

        return reply(interaction, '', { embeds: [embed], isUserBlacklisted, rateLimiter });

      } catch (err) {
        logger.error('DB error in battle result:', err);
        return reply(interaction, 'Database error occurred during the battle.', { isUserBlacklisted, rateLimiter });
      }
    }, { isUserBlacklisted, rateLimiter })
  }
];

