const rateLimiter = (userId) => checkRateLimit(userId, 'guilds_activities', 5, 10000);

const activitiesHandlers = {
  handleWar: safeReplyWrapper(async (interaction, userId) => {
    if (!isSafeDiscordId(userId)) {
      return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
    }
    const action = interaction.options.getString('action');
    const target = interaction.options.getString('target');
    let guild;
    try {
      guild = await Guild.findOne({
        $or: [
          { owner: userId },
          { officers: userId },
          { members: userId }
        ]
      });
    } catch (err) {
      logger.error('DB error in handleWar Guild.findOne:', err);
      return await reply(interaction, '❌ Database error: Could not load guild data. Please try again later.');
    }
    if (!guild) {
      return await reply(interaction, '❌ You are not a member of any guild!');
    }
    const isOwner = guild.owner === userId;
    const isOfficer = guild.officers.includes(userId);
    switch (action) {
      case 'declare': { 
        if (!isOwner && !isOfficer) {
          return await reply(interaction, '❌ Only guild owners and officers can declare war!');
        }
        if (!target) {
          return await reply(interaction, '❌ Please specify a target guild!');
        }
        let targetGuild;
        try {
          targetGuild = await Guild.findOne({ name: { $regex: new RegExp(`^${target}$`, 'i') } });
        } catch (err) {
          logger.error('DB error in handleWar declare Guild.findOne:', err);
          return await reply(interaction, '❌ Database error: Could not find target guild. Please try again later.');
        }
        if (!targetGuild) {
          return await reply(interaction, '❌ Target guild not found!');
        }
        if (targetGuild._id.toString() === guild._id.toString()) {
          return await reply(interaction, '❌ You cannot declare war on your own guild!');
        }
        if (guild.vault < GUILD_WAR_COST) {
          return await reply(interaction, `❌ Guild vault doesn't have enough coins!\n\n🪙 Vault: ${guild.vault.toLocaleString()} coins\n💸 War cost: ${GUILD_WAR_COST.toLocaleString()} coins`);
        }
        const warEndsAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000); // 7 days
        await performAtomicOperation(async (session) => {
          await Guild.findByIdAndUpdate(guild._id, {
            $inc: { vault: -GUILD_WAR_COST },
            $push: {
              wars: {
                targetGuild: targetGuild.name,
                endsAt: warEndsAt
              }
            }
          }, { session });
        });
        await reply(interaction, `⚔️ **${guild.name}** declared war on **${targetGuild.name}**!`);
        progressQuests(userId, ['guild_war'], interaction).catch(e => logger.error('progressQuests error:', e));
        break;
      }
      case 'status': {
        const activeWars = guild.wars.filter(w => w.status === 'ACTIVE');
        if (activeWars.length === 0) {
          return await reply(interaction, '⚔️ Your guild is not currently at war.');
        }
        const embed = new EmbedBuilder()
          .setTitle(`⚔️ ${guild.name} War Status`)
          .setDescription(`Active wars: ${activeWars.length}`);
        for (const war of activeWars) {
          const timeLeft = war.endsAt.getTime() - Date.now();
          const daysLeft = Math.ceil(timeLeft / (1000 * 60 * 60 * 24));
          embed.addFields({
            name: `War vs ${war.targetGuild}`,
            value: `⏰ Ends in: ${daysLeft} days\n📅 Declared: <t:${Math.floor(war.declaredAt.getTime() / 1000)}:R>`,
            inline: true
          });
        }
        embed.setColor('#ff0000').setTimestamp();
        await reply(interaction, '', { embeds: [embed] });
        progressQuests(userId, ['guild_war'], interaction).catch(e => logger.error('progressQuests error:', e));
        break;
      }
      case 'history': {
        if (guild.warHistory.length === 0) {
          return await reply(interaction, '📜 Your guild has no war history yet.');
        }
        const historyEmbed = new EmbedBuilder()
          .setTitle(`📜 ${guild.name} War History`)
          .setDescription(`Total wars: ${guild.warHistory.length}`);
        const recentWars = guild.warHistory.slice(-5); // Show last 5 wars
        for (const war of recentWars) {
          const resultEmoji = war.result === 'WIN' ? '✅' : war.result === 'LOSS' ? '❌' : '🤝';
          historyEmbed.addFields({
            name: `${resultEmoji} vs ${war.opponent}`,
            value: `Result: ${war.result}\n🪙 Spoils: ${war.spoils.toLocaleString()} coins\n📅 <t:${Math.floor(war.date.getTime() / 1000)}:R>`,
            inline: true
          });
        }
        historyEmbed.setColor('#ffa500').setTimestamp();
        await reply(interaction, '', { embeds: [historyEmbed] });
        progressQuests(userId, ['guild_war'], interaction).catch(e => logger.error('progressQuests error:', e));
        break;
      }
    }
  }, { isUserBlacklisted, rateLimiter }),

