          const hoursUntil = Math.ceil(timeUntil / (1000 * 60 * 60));
          embed.addFields({
            name: `${event.title} (${GUILD_EVENT_TYPES[event.type].name})`,
            value: `📝 ${event.description}\n👥 Participants: ${event.participants.length}\n🪙 Rewards: ${event.rewards.toLocaleString()} coins\n⏰ Starts: ${hoursUntil > 0 ? `<t:${Math.floor(event.scheduledAt.getTime() / 1000)}:R>` : 'Started'}`,
            inline: false
          });
        }
        try {
          embed.setColor(require('../../utils/utils').getUserEmbedColor(user)).setTimestamp();
        } catch (err) {
          logger.warn('Failed to get user embed color in handleEvent:', err);
        }
        await reply(interaction, '', { embeds: [embed] });
        progressQuests(userId, ['guild_event'], interaction).catch(e => logger.error('progressQuests error:', e));
        break;
      }
      case 'create': {
        if (!isOwner && !isOfficer) {
          return await reply(interaction, '❌ Only guild owners and officers can create events!');
        }
        if (!type || !title || !description || !time) {
          return await reply(interaction, '❌ Please provide all event details: type, title, description, and time!');
        }
        if (!GUILD_EVENT_TYPES[type]) {
          return await reply(interaction, '❌ Invalid event type!');
        }
        // Parse time (e.g., "2h", "1d", "3d")
        const timeRegex = /^(\d+)([hd])$/;
        const timeMatch = time.match(timeRegex);
        if (!timeMatch) {
          return await reply(interaction, '❌ Invalid time format! Use format like "2h", "1d", "3d"');
        }
        const timeValue = parseInt(timeMatch[1]);
        const timeUnit = timeMatch[2];
        const timeInMs = timeUnit === 'h' ? timeValue * 60 * 60 * 1000 : timeValue * 24 * 60 * 60 * 1000;
        const scheduledAt = new Date(Date.now() + timeInMs);
        const newEvent = {
          title,
          description,
          type,
          scheduledAt,
          duration: GUILD_EVENT_TYPES[type].duration,
          participants: [userId],
          rewards: 0
        };
        await performAtomicOperation(async (session) => {
          await Guild.findByIdAndUpdate(guild._id, {
            $push: { events: newEvent }
          }, { session });
        });
        await reply(interaction, `✅ Created new event: **${title}**!\n\n📅 Type: ${GUILD_EVENT_TYPES[type].name}\n⏰ Starts: <t:${Math.floor(scheduledAt.getTime() / 1000)}:R>\n👥 You are automatically registered!`);
        progressQuests(userId, ['guild_event'], interaction).catch(e => logger.error('progressQuests error:', e));
        break;
      }
      case 'join': {
        if (guild.events.length === 0) {
          return await reply(interaction, '❌ No events to join!');
        }
        const upcomingEvent = guild.events.find(e => e.scheduledAt > new Date());
        if (!upcomingEvent) {
          return await reply(interaction, '❌ No upcoming events to join!');
        }
        if (upcomingEvent.participants.includes(userId)) {
          return await reply(interaction, '❌ You are already registered for this event!');
        }
        await performAtomicOperation(async (session) => {
          await Guild.updateOne(
            { _id: guild._id, 'events._id': upcomingEvent._id },
            { $push: { 'events.$.participants': userId } },
            { session }
          );
        });
        await reply(interaction, `✅ Joined event: **${upcomingEvent.title}**!\n\n👥 Total participants: ${upcomingEvent.participants.length + 1}`);
        progressQuests(userId, ['guild_event'], interaction).catch(e => logger.error('progressQuests error:', e));
        break;
      }
      case 'start': {
        if (!isOwner && !isOfficer) {
          return await reply(interaction, '❌ Only guild owners and officers can start events!');
        }
        const readyEvent = guild.events.find(e => e.scheduledAt <= new Date() && e.participants.length > 0);
        if (!readyEvent) {
          return await reply(interaction, '❌ No events ready to start!');
        }
        // Calculate rewards based on participants
        const rewardPerParticipant = 1000;
        const totalRewards = readyEvent.participants.length * rewardPerParticipant;
        // Distribute rewards to participants in parallel
        await Promise.all(readyEvent.participants.map(participantId =>
          safeUpdateUser(participantId, {
            $inc: { coins: rewardPerParticipant }
          }).catch(e => logger.error('safeUpdateUser error in handleEvent start:', e))
        ));
        // Remove the event and update stats
        await performAtomicOperation(async (session) => {
          await Guild.findByIdAndUpdate(guild._id, {
            $pull: { events: { _id: readyEvent._id } },
            $inc: { 'statistics.totalEarnings': totalRewards }
          }, { session });
        });
        await reply(interaction, `🎉 Event **${readyEvent.title}** has started!\n\n🪙 Distributed **${totalRewards.toLocaleString()} coins** to ${readyEvent.participants.length} participants!`);
        progressQuests(userId, ['guild_event'], interaction).catch(e => logger.error('progressQuests error:', e));
        break;
      }
    }
  }, { isUserBlacklisted, rateLimiter }),

  handleQuest: safeReplyWrapper(async (interaction, userId) => {
    if (!isSafeDiscordId(userId)) {
      return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
    }
    // Placeholder for handleQuest logic - implement as needed
    await reply(interaction, '⚠️ Guild quests are not yet implemented.');
    progressQuests(userId, ['guild_quest'], interaction).catch(e => logger.error('progressQuests error:', e));
  }, { isUserBlacklisted, rateLimiter })
};

module.exports = activitiesHandlers;

