const advancedHandlers = {
  handleAlliance: safeReplyWrapper(async (interaction, userId) => {
    if (!isSafeDiscordId(userId)) {
      return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
    }
    let user;
    try {
      user = await getUser(userId);
    } catch (err) {
      logger.error('DB error in handleAlliance User.findById:', err);
      return await reply(interaction, '❌ Database error: Could not load user data. Please try again later.');
    }
    const action = interaction.options.getString('action');
    const targetGuildName = interaction.options.getString('guild');
    let guild;
    try {
      guild = await Guild.findOne({
        $or: [
          { owner: userId },
          { officers: userId },
          { members: userId }
        ]
      });
    } catch (err) {
      logger.error('DB error in handleAlliance Guild.findOne:', err);
      return await reply(interaction, '❌ Database error: Could not load guild data. Please try again later.');
    }
    if (!guild) {
      return await reply(interaction, '❌ You are not a member of any guild!');
    }
    const isOwner = guild.owner === userId;
    const isOfficer = guild.officers.includes(userId);
    switch (action) {
      case 'view': {
        if (guild.alliances.length === 0) {
          return await reply(interaction, '❌ Your guild has no alliances!');
        }
        const embed = new EmbedBuilder()
          .setTitle(`🤝 ${guild.name} Alliances`)
          .setDescription(`Allied guilds: ${guild.alliances.filter(a => a.status === 'ACTIVE').length}`);
        for (const alliance of guild.alliances.filter(a => a.status === 'ACTIVE')) {
          let alliedGuild;
          let memberCount = 'Unknown';
          try {
            alliedGuild = await Guild.findById(alliance.guildId);
            memberCount = alliedGuild ? (alliedGuild.members.length + alliedGuild.officers.length + 1) : 'Unknown';
          } catch (err) {
            logger.error('DB error in handleAlliance view Guild.findById:', err);
          }
          embed.addFields({
            name: `🤝 ${alliance.guildName}`,
            value: `👥 Members: ${memberCount}\n📅 Formed: <t:${Math.floor(alliance.formedAt.getTime() / 1000)}:R>\n📊 Status: ${alliance.status}`,
            inline: true
          });
        }
        try {
          embed.setColor(require('../../utils/utils').getUserEmbedColor(user)).setTimestamp();
        } catch (err) {
          logger.warn('Failed to get user embed color in handleAlliance:', err);
        }
        await reply(interaction, '', { embeds: [embed] });
        break;
      }
      case 'propose': {
        if (!isOwner && !isOfficer) {
          return await reply(interaction, '❌ Only guild owners and officers can propose alliances!');
        }
        if (!targetGuildName) {
          return await reply(interaction, '❌ Please specify a guild to propose an alliance with!');
        }
        let targetGuild;
        try {
          targetGuild = await Guild.findOne({ name: { $regex: new RegExp(`^${targetGuildName}$`, 'i') } });
        } catch (err) {
          logger.error('DB error in handleAlliance propose Guild.findOne:', err);
          return await reply(interaction, '❌ Database error: Could not find target guild. Please try again later.');
        }
        if (!targetGuild) {
          return await reply(interaction, '❌ Target guild not found!');
        }
        if (targetGuild._id.toString() === guild._id.toString()) {
          return await reply(interaction, '❌ You cannot form an alliance with yourself!');
        }
        // Check if already allied
        const existingAlliance = guild.alliances.find(a => a.guildId === targetGuild._id.toString() && a.status === 'ACTIVE');
        if (existingAlliance) {
          return await reply(interaction, '❌ Your guild is already allied with this guild!');
        }
        // Check if target guild has pending alliance
        const pendingAlliance = targetGuild.alliances.find(a => a.guildId === guild._id.toString() && a.status === 'PENDING');
        if (pendingAlliance) {
          return await reply(interaction, '❌ You already have a pending alliance request with this guild!');
        }
        // Create pending alliance request
        const allianceRequest = {
          guildId: targetGuild._id.toString(),
          guildName: targetGuild.name,
          formedAt: new Date(),
          status: 'PENDING'
        };
        try {
          await Guild.findByIdAndUpdate(targetGuild._id, {
            $push: { alliances: allianceRequest }
          });
        } catch (err) {
          logger.error('DB error in handleAlliance propose Guild.findByIdAndUpdate:', err);
          return await reply(interaction, '❌ Database error: Could not propose alliance. Please try again later.');
        }
        await reply(interaction, `✅ Alliance proposal sent to **${targetGuild.name}**!\n\n📝 The guild owner/officers will need to accept the alliance.`);
        break;
      }
      case 'accept': {
        if (!isOwner && !isOfficer) {
          return await reply(interaction, '❌ Only guild owners and officers can accept alliances!');
        }
        if (!targetGuildName) {
          return await reply(interaction, '❌ Please specify a guild to accept alliance from!');
        }
        let targetGuild;
        try {
          targetGuild = await Guild.findOne({ name: { $regex: new RegExp(`^${targetGuildName}$`, 'i') } });
        } catch (err) {
          logger.error('DB error in handleAlliance accept Guild.findOne:', err);
          return await reply(interaction, '❌ Database error: Could not find target guild. Please try again later.');
        }
        if (!targetGuild) {
          return await reply(interaction, '❌ Target guild not found!');
        }
        // Find pending alliance request
        const pendingAlliance = guild.alliances.find(a => a.guildId === targetGuild._id.toString() && a.status === 'PENDING');
        if (!pendingAlliance) {
          return await reply(interaction, '❌ No pending alliance request from this guild!');
        }
        try {
          // Accept the alliance (update both guilds) - ATOMIC
          await executeAtomic([
            async (session) => {
              await Guild.updateOne(
                { _id: guild._id, 'alliances.guildId': targetGuild._id.toString() },
                { $set: { 'alliances.$.status': 'ACTIVE' } },
                { session }
              );
            },
            async (session) => {
              // Create reciprocal alliance
              const reciprocalAlliance = {
                guildId: guild._id.toString(),
                guildName: guild.name,
                formedAt: new Date(),
                status: 'ACTIVE'
              };
              await Guild.findByIdAndUpdate(targetGuild._id, {
                $push: { alliances: reciprocalAlliance }
              }, { session });
            }
          ], null, { context: 'guild_alliance_accept' });
        } catch (err) {
          logger.error('DB error in handleAlliance accept update:', err);
          return await reply(interaction, '❌ Database error: Could not accept alliance. Please try again later.');
        }
        await reply(interaction, `✅ Alliance formed with **${targetGuild.name}**!\n\n🤝 Both guilds are now allied and can share benefits.`);
        break;
      }
      case 'reject': {
        if (!isOwner && !isOfficer) {
          return await reply(interaction, '❌ Only guild owners and officers can reject alliances!');
        }
        if (!targetGuildName) {
          return await reply(interaction, '❌ Please specify a guild to reject alliance from!');
        }
        let targetGuild;
        try {
          targetGuild = await Guild.findOne({ name: { $regex: new RegExp(`^${targetGuildName}$`, 'i') } });
        } catch (err) {
          logger.error('DB error in handleAlliance reject Guild.findOne:', err);
          return await reply(interaction, '❌ Database error: Could not find target guild. Please try again later.');
        }
        if (!targetGuild) {
          return await reply(interaction, '❌ Target guild not found!');
        }
        try {
          // Remove pending alliance request
          await Guild.findByIdAndUpdate(guild._id, {
            $pull: { alliances: { guildId: targetGuild._id.toString(), status: 'PENDING' } }
          });
        } catch (err) {
          logger.error('DB error in handleAlliance reject Guild.findByIdAndUpdate:', err);
          return await reply(interaction, '❌ Database error: Could not reject alliance. Please try again later.');
        }
        await reply(interaction, `❌ Alliance request from **${targetGuild.name}** rejected.`);
        break;
      }
      case 'break': {
        if (!isOwner && !isOfficer) {
          return await reply(interaction, '❌ Only guild owners and officers can break alliances!');
        }
        if (!targetGuildName) {
          return await reply(interaction, '❌ Please specify a guild to break alliance with!');
        }
        let targetGuild;
        try {
          targetGuild = await Guild.findOne({ name: { $regex: new RegExp(`^${targetGuildName}$`, 'i') } });
        } catch (err) {
          logger.error('DB error in handleAlliance break Guild.findOne:', err);
          return await reply(interaction, '❌ Database error: Could not find target guild. Please try again later.');
        }
        if (!targetGuild) {
          return await reply(interaction, '❌ Target guild not found!');
        }
        // Check if actually allied
        const existingAlliance = guild.alliances.find(a => a.guildId === targetGuild._id.toString() && a.status === 'ACTIVE');
        if (!existingAlliance) {
          return await reply(interaction, '❌ Your guild is not allied with this guild!');
        }
        try {
          // Break alliance (update both guilds) - ATOMIC
          await executeAtomic([
            async (session) => {
              await Guild.updateOne(
                { _id: guild._id, 'alliances.guildId': targetGuild._id.toString() },
                { $set: { 'alliances.$.status': 'BROKEN' } },
                { session }
              );
            },
            async (session) => {
              await Guild.updateOne(
                { _id: targetGuild._id, 'alliances.guildId': guild._id.toString() },
                { $set: { 'alliances.$.status': 'BROKEN' } },
                { session }
              );
            }
          ], null, { context: 'guild_alliance_break' });
        } catch (err) {
          logger.error('DB error in handleAlliance break update:', err);
          return await reply(interaction, '❌ Database error: Could not break alliance. Please try again later.');
        }
        await reply(interaction, `💔 Alliance with **${targetGuild.name}** has been broken.\n\n⚠️ Both guilds are no longer allied.`);
        break;
      }
      case 'pending': {
        const pendingAlliances = guild.alliances.filter(a => a.status === 'PENDING');
        if (pendingAlliances.length === 0) {
          return await reply(interaction, '❌ No pending alliance requests!');
        }
        const embed = new EmbedBuilder()
          .setTitle(`📋 ${guild.name} Pending Alliances`)
          .setDescription(`Pending requests: ${pendingAlliances.length}`);
        for (const alliance of pendingAlliances) {
          embed.addFields({
