  handleTerritory: safeReplyWrapper(async (interaction, userId) => {
    if (!isSafeDiscordId(userId)) {
      return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
    }
    const action = interaction.options.getString('action');
    const type = interaction.options.getString('type');
    const CLAIM_COSTS = {
      MINING: 120000,
      TRADING: 150000,
      DEFENSIVE: 80000,
      FARMING: 100000
    };
    const claimCost = CLAIM_COSTS[type] || 100000;
    // Find the user's guild
    let guild;
    try {
      guild = await Guild.findOne({
        $or: [
          { owner: userId },
          { officers: userId },
          { members: userId }
        ]
      });
    } catch (err) {
      logger.error('DB error in handleTerritory Guild.findOne:', err);
      return await reply(interaction, '❌ Database error: Could not load guild data. Please try again later.');
    }
    if (!guild) return await reply(interaction, '❌ You are not a member of any guild!');
    const isOwner = guild.owner === userId;
    const isOfficer = guild.officers.includes(userId);
    if (action === 'view') {
      if (!guild.territories || guild.territories.length === 0) {
        return await reply(interaction, '🏞️ Your guild has no territories yet! Use `/guild territory claim <type>` to claim one.');
      }
      const embed = new EmbedBuilder()
        .setTitle(`🏞️ ${guild.name} Territories`)
        .setDescription('Your guild territories and their status:');
      for (const terr of guild.territories) {
        const terrType = GUILD_TERRITORY_TYPES[terr.type];
        const lastCollected = terr.lastCollected ? new Date(terr.lastCollected) : new Date(terr.claimedAt);
        const nextCollect = new Date(lastCollected.getTime() + 24 * 60 * 60 * 1000);
        const canCollect = Date.now() >= nextCollect.getTime();
        embed.addFields({
          name: `${terrType?.name || terr.type}`,
          value: `💰 Income: ${terrType?.baseIncome || terr.income} coins/day\n📅 Claimed: <t:${Math.floor(new Date(terr.claimedAt).getTime()/1000)}:d>\n⏰ Next Collect: ${canCollect ? 'Ready!' : `<t:${Math.floor(nextCollect.getTime()/1000)}:R>`}`,
          inline: false
        });
      }
      embed.setColor('#4caf50').setTimestamp();
      return await reply(interaction, '', { embeds: [embed] });
    }
    if (action === 'claim') {
      if (!isOwner && !isOfficer) return await reply(interaction, '❌ Only guild owners and officers can claim territories!');
      if (!type || !GUILD_TERRITORY_TYPES[type]) return await reply(interaction, '❌ Invalid territory type!');
      // Each guild can own up to 5 of each territory type
      const typeCount = (guild.territories || []).filter(t => t.type === type).length;
      if (typeCount >= 5) {
        return await reply(interaction, `❌ Your guild already owns the maximum of 5 ${GUILD_TERRITORY_TYPES[type].name} territories!`);
      }
      // First 3 territory claims (any type) are free, 4th+ cost coins
      let isFree = (guild.territories?.length || 0) < 3;
      if (!isFree && guild.vault < claimCost) {
        return await reply(interaction, `❌ Guild vault doesn't have enough coins!\n\n💰 Vault: ${guild.vault.toLocaleString()} coins\n💸 Claim cost: ${claimCost.toLocaleString()} coins`);
      }
      const newTerritory = {
        name: GUILD_TERRITORY_TYPES[type].name,
        type,
        claimedAt: new Date(),
        income: GUILD_TERRITORY_TYPES[type].baseIncome,
        lastCollected: new Date()
      };
      await executeAtomic([
        async (session) => {
          await Guild.findByIdAndUpdate(guild._id, {
            $push: { territories: newTerritory },
            ...(isFree ? {} : { $inc: { vault: -claimCost } })
          }, { session });
        }
      ], null, { context: 'guild_territory_claim' });
      return await reply(interaction, `✅ Claimed **${GUILD_TERRITORY_TYPES[type].name}** for your guild!\n\n${isFree ? '🎉 This claim was free (first 3 territories are free)!' : `💸 Cost: ${claimCost.toLocaleString()} coins`}`);
    }
    if (action === 'collect') {
      if (!isOwner && !isOfficer) return await reply(interaction, '❌ Only guild owners and officers can collect territory income!');
      if (!type || !GUILD_TERRITORY_TYPES[type]) return await reply(interaction, '❌ Invalid territory type!');
      const terr = (guild.territories || []).find(t => t.type === type);
      if (!terr) return await reply(interaction, `❌ Your guild does not own a ${GUILD_TERRITORY_TYPES[type].name}!`);
      const lastCollected = terr.lastCollected ? new Date(terr.lastCollected) : new Date(terr.claimedAt);
      const nextCollect = new Date(lastCollected.getTime() + 24 * 60 * 60 * 1000);
      if (Date.now() < nextCollect.getTime()) {
        return await reply(interaction, `⏳ You can collect from this territory <t:${Math.floor(nextCollect.getTime()/1000)}:R>.`);
      }
      try {
        await Guild.updateOne(
          { _id: guild._id, 'territories.type': type },
          {
            $inc: { vault: terr.income },
            $set: { 'territories.$.lastCollected': new Date() }
          }
        );
      } catch (err) {
        logger.error('DB error in handleTerritory collect Guild.updateOne:', err);
        return await reply(interaction, '❌ Database error: Could not collect territory income. Please try again later.');
      }
      return await reply(interaction, `💰 Collected **${terr.income} coins** from your ${GUILD_TERRITORY_TYPES[type].name}! Coins added to guild vault.`);
    }
    return await reply(interaction, '❌ Invalid action for /guild territory.');
  }, { isUserBlacklisted, rateLimiter }),

  handleBuilding: safeReplyWrapper(async (interaction, userId) => {
    if (!isSafeDiscordId(userId)) {
      return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
    }
