  handleCreate: safeReplyWrapper(async (interaction, userId) => {
    if (!isSafeDiscordId(userId)) {
      return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
    }
    try {
      const guildName = interaction.options.getString('name');
      const description = interaction.options.getString('description') || '';
      if (!guildName || guildName.length < 3 || guildName.length > MAX_GUILD_NAME_LENGTH) {
        return await reply(interaction, `❌ Guild name must be between 3 and ${MAX_GUILD_NAME_LENGTH} characters long.`);
      }
      if (description.length > MAX_GUILD_DESCRIPTION_LENGTH) {
        return await reply(interaction, `❌ Guild description must be ${MAX_GUILD_DESCRIPTION_LENGTH} characters or less.`);
      }
      let existingGuild;
      try {
        existingGuild = await Guild.findOne({
          $or: [
            { owner: userId },
            { officers: userId },
            { members: userId }
          ]
        });
      } catch (err) {
        logger.error('DB error in handleCreate Guild.findOne (existingGuild):', err);
        return await reply(interaction, '❌ Database error: Could not check your guild status. Please try again later.');
      }
      if (existingGuild) {
        return await reply(interaction, `❌ You are already a member of **${existingGuild.name}**. Leave your current guild first.`);
      }
      let existingGuildName;
      try {
        existingGuildName = await Guild.findOne({ name: guildName });
      } catch (err) {
        logger.error('DB error in handleCreate Guild.findOne (guildName):', err);
        return await reply(interaction, '❌ Database error: Could not check guild name. Please try again later.');
      }
      if (existingGuildName) {
        return await reply(interaction, '❌ A guild with that name already exists. Please choose a different name.');
      }
      let user;
      try {
        user = await User.findById(userId);
      } catch (err) {
        logger.error('DB error in handleCreate User.findById:', err);
        return await reply(interaction, '❌ Database error: Could not load user data. Please try again later.');
      }
      if (!user) {
        return await reply(interaction, '❌ User data not found. Please try again.');
      }
      if (!hasGuildTicket(user)) {
        return await reply(interaction, `❌ You need a **Guild Ticket** to create a guild!\n\n🪙 Cost: ${GUILD_TICKET_PRICE.toLocaleString()} coins\n\nYou can buy one from the shop with /shop.`);
      }
      const totalCost = GUILD_TICKET_PRICE + GUILD_CREATION_COST;
      if (user.coins < totalCost) {
        return await reply(interaction, `❌ You need ${totalCost.toLocaleString()} coins to create a guild!\n\n🪙 Guild Ticket: ${GUILD_TICKET_PRICE.toLocaleString()} coins\n💸 Creation Cost: ${GUILD_CREATION_COST.toLocaleString()} coins\n💰 Your Balance: ${user.coins.toLocaleString()} coins`);
      }

      const guildData = {
        name: guildName,
        description: description,
        owner: userId,
        members: [],
        officers: [],
        createdAt: new Date(),
        level: 1,
        xp: 0,
        vault: 0,
        treasury: 0,
        businesses: [],
        wars: [],
        alliances: [],
        events: [],
        territories: [],
        applications: [],
        activityLog: [],
        settings: {
          public: true,
          autoAccept: false,
          minLevel: 0,
          minCoins: 0,
          allowApplications: true,
          loggingEnabled: false,
          logChannelId: null
        }
      };

      const userData = {
        $inc: { coins: -totalCost },
        $set: { guildId: null, guildRole: null } // Will be set after guild creation
      };

      try {
        const newGuild = await atomicGuildCreation(userId, guildData, userData);

        // Remove Guild Ticket and set guild info
        await removeItemFromInventory(userId, 'Guild Ticket', 1);
        await performAtomicOperation(async (session) => {
          await User.findByIdAndUpdate(userId, {
            $set: { guildId: newGuild._id, guildRole: 'owner' }
          }, { session });
        });

        // Log the activity
        await logGuildActivity(newGuild._id, userId, interaction.user.username, 'guild_created', `Created guild "${guildName}"`);

        const embed = new EmbedBuilder()
          .setTitle('🏰 Guild Created!')
          .setDescription(`Congratulations! You have successfully created **${guildName}**!`)
          .addFields(
            { name: '👑 Owner', value: `<@${userId}>`, inline: true },
            { name: '📝 Description', value: description || 'No description', inline: true },
            { name: '🪙 Cost', value: `${totalCost.toLocaleString()} coins`, inline: true },
            { name: '📅 Created', value: `<t:${Math.floor(Date.now() / 1000)}:F>`, inline: true }
          )
          .setColor(0x00ff00)
          .setTimestamp();
        try {
          embed.setColor(require('../../utils/utils').getUserEmbedColor(user));
        } catch (err) {
          logger.error('Error getting user embed color in handleCreate:', err);
        }
        await reply(interaction, '', { embeds: [embed] });
      } catch (err) {
        logger.error('DB error in handleCreate atomicGuildCreation:', err);
        return await reply(interaction, '❌ Database error: Could not create guild. Please try again later.');
      }
    } catch (error) {
      logger.error('Error in handleCreate:', error);
      return await reply(interaction, '❌ An unexpected error occurred. Please try again later.');
    }
