async function sendGuildLog(message, guildId = null) {
  if (guildId) {
    let guild;
    try {
      guild = await Guild.findById(guildId);
    } catch (err) {
      logger.error('DB error in sendGuildLog Guild.findById:', err);
      return;
    }
    if (guild?.settings?.loggingEnabled && guild?.settings?.logChannelId) {
      try {
        // Note: In a real implementation, you'd need to pass the Discord client
        // For now, we'll just log to console and the guild's log channel would be set
        logger.info(`[Guild ${guild.name}] ${message}`);
        // In production: client.channels.cache.get(guild.settings.logChannelId)?.send(message);
      } catch (e) {
        logger.warn('sendGuildLog failed:', e);
      }
    }
  } else {
    // Fallback to global logging
    const channelId = process.env.GUILD_LOG_CHANNEL_ID;
    if (channelId) {
      try {
        logger.info('Guild Log:', message);
        // In production: client.channels.cache.get(channelId)?.send(message);
      } catch (e) {
        logger.warn('sendGuildLog failed:', e);
      }
    }
  }
}

