        if ((guild.businesses || []).length === 0) {
          return await reply(interaction, '❌ Your guild has no businesses to collect from!');
        }
        let totalCollected = 0;
        const updatedBusinesses = (guild.businesses || []).map(business => {
          const businessInfo = GUILD_BUSINESSES[business.type];
          const timeSinceCollection = Date.now() - business.lastCollected.getTime();
          const hoursSinceCollection = Math.floor(timeSinceCollection / (1000 * 60 * 60));
          const income = businessInfo.baseIncome * business.level * business.efficiency * hoursSinceCollection;
          totalCollected += income;
          return {
            ...business.toObject(),
            lastCollected: new Date()
          };
        });
        try {
          await Guild.findByIdAndUpdate(guild._id, {
            businesses: updatedBusinesses,
            $inc: { vault: totalCollected, 'statistics.totalEarnings': totalCollected }
          });
