const managementHandlers = {
  handleInvite: safeReplyWrapper(async (interaction, userId) => {
    if (!isSafeDiscordId(userId)) {
      return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
    }
    const targetUser = interaction.options.getUser('user');
    const maxUses = interaction.options.getInteger('max_uses') || 1;
    const expiresIn = interaction.options.getString('expires_in') || '24h'; // Default 24 hours

    if (!targetUser) return await reply(interaction, '❌ Please specify a user to invite.');

    const guild = await Guild.findOne({
      $or: [
        { owner: userId },
        { officers: userId }
      ]
    });

    if (!guild) return await reply(interaction, '❌ Only guild owners or officers can invite members.');

    if (guild.members.includes(targetUser.id) || guild.officers.includes(targetUser.id) || guild.owner === targetUser.id)
      return await reply(interaction, '❌ That user is already a member of your guild.');

    // Check guild member limit
    const memberCount = guild.members.length + guild.officers.length + 1;
    if (memberCount >= MAX_GUILD_MEMBERS) return await reply(interaction, `❌ Guild is full (${MAX_GUILD_MEMBERS} members maximum).`);

    // Parse expiration time
    const timeRegex = /^(\d+)([hd])$/;
    const timeMatch = expiresIn.match(timeRegex);
    if (!timeMatch) return await reply(interaction, '❌ Invalid expiration format! Use format like "2h", "1d", "3d"');

    const timeValue = parseInt(timeMatch[1]);
    const timeUnit = timeMatch[2];
    const timeInMs = timeUnit === 'h' ? timeValue * 60 * 60 * 1000 : timeValue * 24 * 60 * 60 * 1000;
    const expiresAt = new Date(Date.now() + timeInMs);

    // Generate invite code
    const inviteCode = secureRandomString(6).toUpperCase();

    // Create invite
    const invite = {
      code: inviteCode,
      createdBy: userId,
      createdAt: new Date(),
      expiresAt: expiresAt,
      uses: 0,
      maxUses: maxUses
    };

    try {
      await Guild.findByIdAndUpdate(guild._id, {
        $push: { invites: invite }
      });

      const embed = new EmbedBuilder()
        .setTitle('📨 Guild Invitation Created')
        .setDescription(`Invitation for **${guild.name}**`)
        .addFields(
          { name: '👤 Invited User', value: `<@${targetUser.id}>`, inline: true },
          { name: '🔗 Invite Code', value: `\`${inviteCode}\``, inline: true },
          { name: '⏰ Expires', value: `<t:${Math.floor(expiresAt.getTime() / 1000)}:R>`, inline: true },
          { name: '📊 Uses', value: `0/${maxUses}`, inline: true }
        )
        .setColor(0x00ff00)
        .setTimestamp();

      await reply(interaction, '', { embeds: [embed] });
    } catch (err) {
      logger.error('DB error in handleInvite:', err);
      return await reply(interaction, '❌ Database error: Could not create invitation. Please try again later.');
    }

    progressQuests(userId, ['guild_invite'], interaction).catch(e => logger.error('progressQuests error:', e));
