    // Find guild with this invite code
    const guild = await Guild.findOne({
      'invites.code': inviteCode,
      'invites.expiresAt': { $gt: new Date() }
    });
    if (!guild) return await reply(interaction, '❌ Invalid or expired invite code.');
    const invite = guild.invites.find(inv => inv.code === inviteCode);
    if (!invite) return await reply(interaction, '❌ Invalid invite code.');
    if (invite.uses >= invite.maxUses) return await reply(interaction, '❌ This invite code has reached its maximum uses.');
    // Check if user is already in a guild
    const existingGuild = await Guild.findOne({
      $or: [
        { owner: userId },
