// Utility function to log guild activities
async function logGuildActivity(guildId, userId, username, action, details = '') {
  try {
    await Guild.findByIdAndUpdate(guildId, {
      $push: {
        activityLog: {
          action: action,
          userId: userId,
          username: username,
          details: details,
          timestamp: new Date()
        }
      }
    });
  } catch (err) {
    logger.error('Error logging guild activity:', err);
  }
}

