      });
      await reply(interaction, `✅ Application sent to **${guild.name}**! Wait for an officer or owner to review your request.`);
      progressQuests(userId, ['guild_apply'], interaction).catch(e => logger.error('progressQuests error:', e));
    } catch (err) {
      logger.error('DB error in handleApply:', err);
      return await reply(interaction, '❌ Database error: Could not submit application. Please try again later.');
    }
  }, { isUserBlacklisted, rateLimiter }),

  handleApplications: safeReplyWrapper(async (interaction, userId) => {
    const action = interaction.options.getString('action') || 'view';
    const targetUserId = interaction.options.getString('user');

    // Find user's guild (must be owner or officer)
    const guild = await Guild.findOne({
      $or: [
        { owner: userId },
        { officers: userId }
      ]
    });

    if (!guild) return await reply(interaction, '❌ Only guild owners and officers can manage applications.');

    if (!isSafeDiscordId(userId)) {
      return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
    }

    if (action === 'view') {
      const pendingApplications = guild.applications.filter(app => app.status === 'PENDING');

      if (pendingApplications.length === 0) {
        return await reply(interaction, '📋 No pending applications.');
      }

      const embed = new EmbedBuilder()
        .setTitle(`📋 Pending Applications - ${guild.name}`)
        .setDescription(`You have ${pendingApplications.length} pending application(s).`)
        .setColor(0xffa500);

      for (const app of pendingApplications.slice(0, 10)) { // Show max 10
        embed.addFields({
          name: `👤 ${app.username}`,
          value: `Applied: <t:${Math.floor(app.appliedAt.getTime() / 1000)}:R>\nUser ID: ${app.userId}`,
          inline: true
        });
      }

      embed.setTimestamp();
      await reply(interaction, '', { embeds: [embed] });

    } else if (action === 'accept' || action === 'reject') {
      if (!targetUserId) return await reply(interaction, '❌ Please specify a user ID to accept/reject.');

      const application = guild.applications.find(app => app.userId === targetUserId && app.status === 'PENDING');
      if (!application) return await reply(interaction, '❌ No pending application found for that user.');

      if (action === 'accept') {
        // Check if user still has a Guild Ticket
        const user = await User.findById(targetUserId);
        if (!user || !hasGuildTicket(user)) {
          return await reply(interaction, '❌ That user no longer has a Guild Ticket required to join.');
        }

        // Check if guild is still not full
        const memberCount = guild.members.length + guild.officers.length + 1;
        if (memberCount >= MAX_GUILD_MEMBERS) {
          return await reply(interaction, `❌ Guild is now full (${MAX_GUILD_MEMBERS} members maximum).`);
        }

        if (!isSafeDiscordId(targetUserId)) {
          return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
        }

        try {
          // Use atomic operation for all DB changes
          await atomicGuildMemberAcceptance(guild._id, targetUserId, userId);
          await reply(interaction, `✅ Accepted **${application.username}** into **${guild.name}**!`);
          progressQuests(userId, ['guild_accept'], interaction).catch(e => logger.error('progressQuests error:', e));
        } catch (err) {
          logger.error('DB error in handleApplications accept (atomic):', err);
          return await reply(interaction, '❌ Database error: Could not accept application. Please try again later.');
        }

      } else { // reject
        if (!isSafeDiscordId(targetUserId)) {
          return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
        }

        try {
          await executeAtomic([
            async (session) => {
              await Guild.updateOne(
                { _id: guild._id, 'applications.userId': targetUserId },
                { 
                  $set: { 
                    'applications.$.status': 'REJECTED',
                    'applications.$.reviewedBy': userId,
                    'applications.$.reviewedAt': new Date()
                  }
                },
                { session }
              );
            }
          ], null, { context: 'guild_application_reject' });

          await reply(interaction, `❌ Rejected **${application.username}**'s application to **${guild.name}**.`);
          progressQuests(userId, ['guild_reject'], interaction).catch(e => logger.error('progressQuests error:', e));
        } catch (err) {
          logger.error('DB error in handleApplications reject:', err);
          return await reply(interaction, '❌ Database error: Could not reject application. Please try again later.');
        }
      }
    } else {
      return await reply(interaction, '❌ Invalid action. Use "view", "accept", or "reject".');
    }
  }, { isUserBlacklisted, rateLimiter })
};

module.exports = membersHandlers;

