const { EmbedBuilder } = require('discord.js');
const { User, Guild } = require('../../database/db');
const { withSafeReply, isUserBlacklisted, getUser, isSafeDiscordId, progressQuests } = require('../../utils/utils');
const { withSafeReply: safeReplyWrapper } = require('../../utils/safeReply');
const { reply } = require('../../utils/formatting');
const logger = require('../../logger');
const { checkRateLimit } = require('../../utils/rateLimiting');

const rateLimiter = (userId) => checkRateLimit(userId, 'guilds_search', 5, 10000);

const searchHandlers = {
  handleSearch: safeReplyWrapper(async (interaction, userId) => {
    if (!isSafeDiscordId(userId)) {
      return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
    }

    let user;
    try {
      user = await getUser(userId);
    } catch (err) {
      logger.error('DB error in handleSearch User.findById:', err);
      return await reply(interaction, '❌ Database error: Could not load user data. Please try again later.');
    }

    const query = interaction.options.getString('query');
    const type = interaction.options.getString('type') || 'name';

    if (!query) {
      return await reply(interaction, '❌ Please provide a search query!');
    }

    let searchResults;
    try {
      switch (type) {
        case 'name':
          searchResults = await Guild.find({
            name: { $regex: new RegExp(query, 'i') }
          }).limit(10);
          break;
        case 'owner':
          // First find users with matching username
          const matchingUsers = await User.find({
            username: { $regex: new RegExp(query, 'i') }
          }).limit(5);
          const userIds = matchingUsers.map(u => u._id);
          searchResults = await Guild.find({
            owner: { $in: userIds }
          }).limit(10);
          break;
        case 'member':
          // Find users with matching username
          const memberUsers = await User.find({
            username: { $regex: new RegExp(query, 'i') }
          }).limit(5);
          const memberUserIds = memberUsers.map(u => u._id);
          searchResults = await Guild.find({
            $or: [
              { owner: { $in: memberUserIds } },
              { officers: { $in: memberUserIds } },
              { members: { $in: memberUserIds } }
            ]
          }).limit(10);
          break;
        default:
          return await reply(interaction, '❌ Invalid search type! Use "name", "owner", or "member".');
      }
    } catch (err) {
      logger.error('DB error in handleSearch Guild.find:', err);
      return await reply(interaction, '❌ Database error: Could not search guilds. Please try again later.');
    }

    if (searchResults.length === 0) {
      return await reply(interaction, `❌ No guilds found matching "${query}" in ${type} search.`);
    }

    const embed = new EmbedBuilder()
      .setTitle(`🔍 Guild Search Results`)
      .setDescription(`Found ${searchResults.length} guild(s) matching "${query}"`)
      .setFooter({ text: `Search type: ${type}` });

    for (const guild of searchResults) {
      let ownerName = 'Unknown';
      try {
        const owner = await User.findById(guild.owner);
        ownerName = owner ? owner.username : 'Unknown';
      } catch (err) {
        logger.error('DB error in handleSearch User.findById:', err);
      }

      const memberCount = (guild.members?.length || 0) + (guild.officers?.length || 0) + 1;
      const level = Math.floor((guild.xp || 0) / 1000) + 1;

      embed.addFields({
        name: `${guild.name} (Level ${level})`,
        value: `👑 Owner: ${ownerName}\n👥 Members: ${memberCount}\n🪙 Vault: ${(guild.vault || 0).toLocaleString()} coins\n📅 Created: <t:${Math.floor(new Date(guild.createdAt).getTime()/1000)}:d>`,
        inline: true
      });
    }

    try {
      embed.setColor(require('../../utils/utils').getUserEmbedColor(user)).setTimestamp();
    } catch (err) {
      logger.warn('Failed to get user embed color in handleSearch:', err);
    }

    await reply(interaction, '', { embeds: [embed] });
    progressQuests(userId, ['guild_search'], interaction).catch(e => logger.error('progressQuests error:', e));
  }, { isUserBlacklisted, rateLimiter }),

  handleLeaderboard: safeReplyWrapper(async (interaction, userId) => {
    if (!isSafeDiscordId(userId)) {
      return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
    }

    let user;
    try {
      user = await getUser(userId);
    } catch (err) {
      logger.error('DB error in handleLeaderboard User.findById:', err);
      return await reply(interaction, '❌ Database error: Could not load user data. Please try again later.');
    }

    const type = interaction.options.getString('type') || 'level';
    const page = interaction.options.getInteger('page') || 1;

    if (page < 1 || page > 10) {
      return await reply(interaction, '❌ Page must be between 1 and 10!');
    }

    const limit = 10;
    const skip = (page - 1) * limit;

    let sortCriteria;
    let title;
    let description;

    switch (type) {
      case 'level':
        sortCriteria = { xp: -1 };
        title = '🏆 Guild Level Leaderboard';
        description = 'Top guilds by experience level';
        break;
      case 'members':
        sortCriteria = { 'members': -1 };
        title = '👥 Guild Member Leaderboard';
        description = 'Top guilds by member count';
        break;
      case 'vault':
        sortCriteria = { vault: -1 };
        title = '🪙 Guild Vault Leaderboard';
        description = 'Top guilds by vault balance';
        break;
      case 'territories':
        sortCriteria = { 'territories': -1 };
        title = '🏞️ Guild Territory Leaderboard';
        description = 'Top guilds by territory count';
        break;
      case 'alliances':
        sortCriteria = { 'alliances': -1 };
        title = '🤝 Guild Alliance Leaderboard';
        description = 'Top guilds by active alliances';
        break;
      default:
        return await reply(interaction, '❌ Invalid leaderboard type! Use "level", "members", "vault", "territories", or "alliances".');
    }

    let guilds;
    try {
      guilds = await Guild.find({})
        .sort(sortCriteria)
        .skip(skip)
        .limit(limit);
    } catch (err) {
      logger.error('DB error in handleLeaderboard Guild.find:', err);
      return await reply(interaction, '❌ Database error: Could not load leaderboard. Please try again later.');
    }

    if (guilds.length === 0) {
      return await reply(interaction, '❌ No guilds found for this leaderboard.');
    }

    const embed = new EmbedBuilder()
      .setTitle(title)
      .setDescription(description)
      .setFooter({ text: `Page ${page} • Use /guild leaderboard <type> <page> to navigate` });

    for (let i = 0; i < guilds.length; i++) {
      const guild = guilds[i];
      const rank = skip + i + 1;
      const rankEmoji = rank === 1 ? '🥇' : rank === 2 ? '🥈' : rank === 3 ? '🥉' : `${rank}.`;

      let ownerName = 'Unknown';
      try {
        const owner = await User.findById(guild.owner);
        ownerName = owner ? owner.username : 'Unknown';
      } catch (err) {
        logger.error('DB error in handleLeaderboard User.findById:', err);
      }

      const memberCount = (guild.members?.length || 0) + (guild.officers?.length || 0) + 1;
      const level = Math.floor((guild.xp || 0) / 1000) + 1;
      const activeAlliances = (guild.alliances || []).filter(a => a.status === 'ACTIVE').length;

      let value = `👑 Owner: ${ownerName}\n👥 Members: ${memberCount}\n📊 Level: ${level}`;

      switch (type) {
        case 'level':
          value += `\n⭐ Experience: ${(guild.xp || 0).toLocaleString()}`;
          break;
        case 'members':
          value += `\n👥 Total Members: ${memberCount}`;
          break;
        case 'vault':
          value += `\n🪙 Vault: ${(guild.vault || 0).toLocaleString()} coins`;
          break;
        case 'territories':
          value += `\n🏞️ Territories: ${(guild.territories?.length || 0)}`;
          break;
        case 'alliances':
          value += `\n🤝 Alliances: ${activeAlliances}`;
          break;
      }

      embed.addFields({
        name: `${rankEmoji} ${guild.name}`,
        value: value,
        inline: false
      });
    }

    try {
      embed.setColor(require('../../utils/utils').getUserEmbedColor(user)).setTimestamp();
    } catch (err) {
      logger.warn('Failed to get user embed color in handleLeaderboard:', err);
    }

    await reply(interaction, '', { embeds: [embed] });
    progressQuests(userId, ['guild_leaderboard'], interaction).catch(e => logger.error('progressQuests error:', e));
  }, { isUserBlacklisted, rateLimiter })
};

module.exports = searchHandlers;

