const { EmbedBuilder } = require('discord.js');
const { User, Guild } = require('../../database/db');
const { withSafeReply, isUserBlacklisted, getUser, isSafeDiscordId, progressQuests } = require('../../utils/utils');
const { withSafeReply: safeReplyWrapper } = require('../../utils/safeReply');
const { reply } = require('../../utils/formatting');
const logger = require('../../logger');
const { checkRateLimit } = require('../../utils/rateLimiting');

const rateLimiter = (userId) => checkRateLimit(userId, 'guilds_settings', 5, 10000);

const settingsHandlers = {
  handleSettings: safeReplyWrapper(async (interaction, userId) => {
    if (!isSafeDiscordId(userId)) {
      return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
    }

    let user;
    try {
      user = await getUser(userId);
    } catch (err) {
      logger.error('DB error in handleSettings User.findById:', err);
      return await reply(interaction, '❌ Database error: Could not load user data. Please try again later.');
    }

    const action = interaction.options.getString('action');
    const setting = interaction.options.getString('setting');
    const value = interaction.options.getString('value');

    // Find the user's guild
    let guild;
    try {
      guild = await Guild.findOne({
        $or: [
          { owner: userId },
          { officers: userId }
        ]
      });
    } catch (err) {
      logger.error('DB error in handleSettings Guild.findOne:', err);
      return await reply(interaction, '❌ Database error: Could not load guild data. Please try again later.');
    }

    if (!guild) {
      return await reply(interaction, '❌ You are not an owner or officer of any guild!');
    }

    const isOwner = guild.owner === userId;

    if (action === 'view') {
      const embed = new EmbedBuilder()
        .setTitle(`⚙️ ${guild.name} Settings`)
        .setDescription('Current guild settings and configuration:')
        .addFields(
          { name: '📝 Description', value: guild.description || 'No description set', inline: false },
          { name: '🔗 Invite Link', value: guild.inviteLink || 'No invite link set', inline: false },
          { name: '🎨 Color', value: guild.color || 'Default', inline: true },
          { name: '📊 Auto-Collect', value: guild.settings?.autoCollect ? '✅ Enabled' : '❌ Disabled', inline: true },
          { name: '📈 Logging', value: guild.settings?.loggingEnabled ? '✅ Enabled' : '❌ Disabled', inline: true },
          { name: '🔒 Private', value: guild.settings?.private ? '✅ Yes' : '❌ No', inline: true },
          { name: '👥 Max Members', value: guild.settings?.maxMembers?.toString() || '50', inline: true },
          { name: '💰 Tax Rate', value: `${guild.settings?.taxRate || 5}%`, inline: true }
        );

      try {
        embed.setColor(require('../../utils/utils').getUserEmbedColor(user)).setTimestamp();
      } catch (err) {
        logger.warn('Failed to get user embed color in handleSettings:', err);
      }

      return await reply(interaction, '', { embeds: [embed] });
    }

    if (action === 'set') {
      if (!isOwner) {
        return await reply(interaction, '❌ Only guild owners can change settings!');
      }

      if (!setting || !value) {
        return await reply(interaction, '❌ Please provide both setting and value!');
      }

      let updateData = {};

      switch (setting.toLowerCase()) {
        case 'description':
          if (value.length > 500) {
            return await reply(interaction, '❌ Description must be 500 characters or less!');
          }
          updateData.description = value;
          break;

        case 'invitelink':
        case 'invite_link':
          // Basic URL validation
          if (!value.startsWith('https://discord.gg/') && !value.startsWith('https://discord.com/invite/')) {
            return await reply(interaction, '❌ Please provide a valid Discord invite link!');
          }
          updateData.inviteLink = value;
          break;

        case 'color':
          // Basic hex color validation
          if (!/^#[0-9A-F]{6}$/i.test(value)) {
            return await reply(interaction, '❌ Please provide a valid hex color (e.g., #FF0000)!');
          }
          updateData.color = value;
          break;

        case 'autocollect':
        case 'auto_collect':
          const autoCollect = value.toLowerCase() === 'true' || value.toLowerCase() === 'yes' || value === '1';
          updateData['settings.autoCollect'] = autoCollect;
          break;

        case 'logging':
          const logging = value.toLowerCase() === 'true' || value.toLowerCase() === 'yes' || value === '1';
          updateData['settings.loggingEnabled'] = logging;
          break;

        case 'private':
          const isPrivate = value.toLowerCase() === 'true' || value.toLowerCase() === 'yes' || value === '1';
          updateData['settings.private'] = isPrivate;
          break;

        case 'maxmembers':
        case 'max_members':
          const maxMembers = parseInt(value);
          if (isNaN(maxMembers) || maxMembers < 5 || maxMembers > 100) {
            return await reply(interaction, '❌ Max members must be between 5 and 100!');
          }
          updateData['settings.maxMembers'] = maxMembers;
          break;

        case 'taxrate':
        case 'tax_rate':
          const taxRate = parseFloat(value);
          if (isNaN(taxRate) || taxRate < 0 || taxRate > 20) {
            return await reply(interaction, '❌ Tax rate must be between 0% and 20%!');
          }
          updateData['settings.taxRate'] = taxRate;
          break;

        default:
          return await reply(interaction, '❌ Invalid setting! Available settings: description, invitelink, color, autocollect, logging, private, maxmembers, taxrate');
      }

      try {
        await Guild.findByIdAndUpdate(guild._id, { $set: updateData });
      } catch (err) {
        logger.error('DB error in handleSettings set Guild.findByIdAndUpdate:', err);
        return await reply(interaction, '❌ Database error: Could not update setting. Please try again later.');
      }

      progressQuests(userId, ['guild_settings'], interaction).catch(e => logger.error('progressQuests error:', e));

      return await reply(interaction, `✅ Updated guild setting: **${setting}** = **${value}**`);
    }

    if (action === 'reset') {
      if (!isOwner) {
        return await reply(interaction, '❌ Only guild owners can reset settings!');
      }

      if (!setting) {
        return await reply(interaction, '❌ Please specify which setting to reset!');
      }

      let updateData = {};

      switch (setting.toLowerCase()) {
        case 'description':
          updateData.description = null;
          break;

        case 'invitelink':
        case 'invite_link':
          updateData.inviteLink = null;
          break;

        case 'color':
          updateData.color = null;
          break;

        case 'autocollect':
        case 'auto_collect':
          updateData['settings.autoCollect'] = false;
          break;

        case 'logging':
          updateData['settings.loggingEnabled'] = false;
          break;

        case 'private':
          updateData['settings.private'] = false;
          break;

        case 'maxmembers':
        case 'max_members':
          updateData['settings.maxMembers'] = 50;
          break;

        case 'taxrate':
        case 'tax_rate':
          updateData['settings.taxRate'] = 5;
          break;

        case 'all':
          updateData = {
            description: null,
            inviteLink: null,
            color: null,
            'settings.autoCollect': false,
            'settings.loggingEnabled': false,
            'settings.private': false,
            'settings.maxMembers': 50,
            'settings.taxRate': 5
          };
          break;

        default:
          return await reply(interaction, '❌ Invalid setting! Available settings: description, invitelink, color, autocollect, logging, private, maxmembers, taxrate, all');
      }

      try {
        await Guild.findByIdAndUpdate(guild._id, { $set: updateData });
      } catch (err) {
        logger.error('DB error in handleSettings reset Guild.findByIdAndUpdate:', err);
        return await reply(interaction, '❌ Database error: Could not reset setting. Please try again later.');
      }

      if (setting.toLowerCase() === 'all') {
        return await reply(interaction, '✅ Reset all guild settings to default values!');
      } else {
        return await reply(interaction, `✅ Reset guild setting: **${setting}** to default value!`);
      }
    }

    return await reply(interaction, '❌ Invalid action for /guild settings. Use "view", "set", or "reset".');
  }, { isUserBlacklisted, rateLimiter })
};

module.exports = settingsHandlers;

const { SlashCommandBuilder, EmbedBuilder } = require('discord.js');
