const { getUser, safeUpdateUser } = require('../../utils/database');
const { MINING_TOOLS, MINING_ORES } = require('./constants');
const logger = require('../../logger');

// Initialize mining data for a user
async function initializeMiningData(userId) {
  try {
    const user = await getUser(userId);
    if (!user) return null;

    if (!user.mining) {
      await safeUpdateUser(userId, {
        mining: {
          level: 1,
          xp: 0,
          totalOresMined: 0,
          totalCoinsEarned: 0,
          lastMined: null,
          currentTool: 'Wooden Pickaxe',
          tools: ['Wooden Pickaxe'],
          ores: {},
          upgrades: {
            efficiency: 0,
            luck: 0,
            depth: 0,
            capacity: 0
          },
          quests: {
            active: [],
            completed: [],
            progress: {}
          },

          team: {
            inTeam: false,
            teamId: null,
            teamStartTime: null
          },
          streaks: {
            current: 0,
            longest: 0,
            lastMined: null
          },
          stats: {
            oresMined: {},
            toolsUsed: {},
            depthsMined: {},
            rareFinds: 0,
            totalMiningTime: 0
          }
        }
      });
    }

    return await getUser(userId);
  } catch (error) {
    logger.error('Error initializing mining data:', error);
    return null;
  }
}

// Get user's mining data
async function getMiningData(userId) {
  try {
    let user = await getUser(userId);
    if (!user) return null;

    if (!user.mining) {
      user = await initializeMiningData(userId);
    }

    // Ensure all required properties exist
    const miningData = user.mining;
    if (miningData) {
      const defaultStructure = {
        level: 1,
        xp: 0,
        totalOresMined: 0,
        totalCoinsEarned: 0,
        lastMined: null,
        currentTool: 'Wooden Pickaxe',
        tools: ['Wooden Pickaxe'],
        ores: {},
        upgrades: {
          efficiency: 0,
          luck: 0,
          depth: 0,
          capacity: 0
        },
        quests: {
          active: [],
          completed: [],
          progress: {}
        },
        team: {
          inTeam: false,
          teamId: null,
          teamStartTime: null
        },
        streaks: {
          current: 0,
          longest: 0,
          lastMined: null
        },
        stats: {
          oresMined: {},
          toolsUsed: {},
          depthsMined: {},
          rareFinds: 0,
          totalMiningTime: 0
        }
      };

      // Merge existing data with default structure to ensure all properties exist
      const mergedData = { ...defaultStructure, ...miningData };

      // Deep merge for nested objects
      mergedData.upgrades = { ...defaultStructure.upgrades, ...miningData.upgrades };
      mergedData.quests = { ...defaultStructure.quests, ...miningData.quests };
      mergedData.team = { ...defaultStructure.team, ...miningData.team };
      mergedData.streaks = { ...defaultStructure.streaks, ...miningData.streaks };
      mergedData.stats = { ...defaultStructure.stats, ...miningData.stats };
      mergedData.ores = { ...defaultStructure.ores, ...miningData.ores };
      mergedData.tools = miningData.tools || defaultStructure.tools;

      // Update the database with the complete structure if it was missing properties
      if (JSON.stringify(mergedData) !== JSON.stringify(miningData)) {
        await safeUpdateUser(userId, { mining: mergedData });
      }

      return mergedData;
    }

    return null;
  } catch (error) {
    logger.error('Error getting mining data:', error);
    return null;
  }
}

// Update mining data
async function updateMiningData(userId, updates) {
  try {
    const user = await getUser(userId);
    if (!user) return false;

    if (!user.mining) {
      await initializeMiningData(userId);
    }

    await safeUpdateUser(userId, { mining: updates });
    return true;
  } catch (error) {
    logger.error('Error updating mining data:', error);
    return false;
  }
}

// Add ore to user's inventory
async function addOre(userId, oreName, amount = 1) {
  try {
    const miningData = await getMiningData(userId);
    if (!miningData) return false;

    const currentAmount = miningData.ores[oreName] || 0;
    const newAmount = currentAmount + amount;

    await updateMiningData(userId, {
      ...miningData,
      ores: {
        ...miningData.ores,
        [oreName]: newAmount
      },
      totalOresMined: miningData.totalOresMined + amount,
      stats: {
        ...miningData.stats,
        oresMined: {
          ...miningData.stats?.oresMined,
          [oreName]: (miningData.stats?.oresMined?.[oreName] || 0) + amount
        }
      }
    });

    return true;
  } catch (error) {
    logger.error('Error adding ore:', error);
    return false;
  }
}

// Remove ore from user's inventory
async function removeOre(userId, oreName, amount = 1) {
  try {
    const miningData = await getMiningData(userId);
    if (!miningData) return false;

    const currentAmount = miningData.ores[oreName] || 0;
    if (currentAmount < amount) return false;

    const newAmount = currentAmount - amount;

    await updateMiningData(userId, {
      ...miningData,
      ores: {
        ...miningData.ores,
        [oreName]: newAmount > 0 ? newAmount : undefined
      }
    });

    return true;
  } catch (error) {
    logger.error('Error removing ore:', error);
    return false;
  }
}

// Add mining XP and level up if needed
async function addMiningXP(userId, xpAmount) {
  try {
    const miningData = await getMiningData(userId);
    if (!miningData) return false;

    const newXP = miningData.xp + xpAmount;
    const newLevel = Math.floor(newXP / 1000) + 1; // Level up every 1000 XP
    const leveledUp = newLevel > miningData.level;

    await updateMiningData(userId, {
      ...miningData,
      xp: newXP,
      level: newLevel
    });

    return { leveledUp, newLevel, newXP };
  } catch (error) {
    logger.error('Error adding mining XP:', error);
    return false;
  }
}

// Update mining streak
async function updateMiningStreak(userId) {
  try {
    const miningData = await getMiningData(userId);
    if (!miningData) return false;

    const now = Date.now();
    const lastMined = miningData.streaks?.lastMined;
    const dayInMs = 24 * 60 * 60 * 1000;

    let newStreak = 1;
    if (lastMined && (now - lastMined) < dayInMs) {
      newStreak = (miningData.streaks?.current || 0) + 1;
    }

    const longestStreak = Math.max(miningData.streaks?.longest || 0, newStreak);

    await updateMiningData(userId, {
      ...miningData,
      streaks: {
        current: newStreak,
        longest: longestStreak,
        lastMined: now
      }
    });

    return { newStreak, longestStreak };
  } catch (error) {
    logger.error('Error updating mining streak:', error);
    return false;
  }
}

// Update quest progress
async function updateQuestProgress(userId, questType, amount = 1) {
  try {
    const miningData = await getMiningData(userId);
    if (!miningData) return false;

    const currentProgress = miningData.quests?.progress?.[questType] || 0;
    const newProgress = currentProgress + amount;

    await updateMiningData(userId, {
      ...miningData,
      quests: {
        ...miningData.quests,
        progress: {
          ...miningData.quests?.progress,
          [questType]: newProgress
        }
      }
    });

    return newProgress;
  } catch (error) {
    logger.error('Error updating quest progress:', error);
    return false;
  }
}

// Complete a quest
async function completeQuest(userId, questId) {
  try {
    const miningData = await getMiningData(userId);
    if (!miningData) return false;

    const activeQuests = miningData.quests?.active?.filter(q => q.id !== questId) || [];
    const completedQuests = [...(miningData.quests?.completed || []), questId];

    await updateMiningData(userId, {
      ...miningData,
      quests: {
        ...miningData.quests,
        active: activeQuests,
        completed: completedQuests
      }
    });

    return true;
  } catch (error) {
    logger.error('Error completing quest:', error);
    return false;
  }
}

// Add tool to user's collection
async function addTool(userId, toolName) {
  try {
    const miningData = await getMiningData(userId);
    if (!miningData) return false;

    if (miningData.tools.includes(toolName)) return false;

    await updateMiningData(userId, {
      ...miningData,
      tools: [...miningData.tools, toolName]
    });

    return true;
  } catch (error) {
    logger.error('Error adding tool:', error);
    return false;
  }
}

// Set current tool
async function setCurrentTool(userId, toolName) {
  try {
    const miningData = await getMiningData(userId);
    if (!miningData) return false;

    if (!miningData.tools.includes(toolName)) return false;

    await updateMiningData(userId, {
      ...miningData,
      currentTool: toolName
    });

    return true;
  } catch (error) {
    logger.error('Error setting current tool:', error);
    return false;
  }
}

// Get user's ore inventory
async function getOreInventory(userId) {
  try {
    const miningData = await getMiningData(userId);
    if (!miningData) return {};

    return miningData.ores || {};
  } catch (error) {
    logger.error('Error getting ore inventory:', error);
    return {};
  }
}

// Get total ore value
async function getTotalOreValue(userId) {
  try {
    const ores = await getOreInventory(userId);
    let totalValue = 0;

    for (const [oreName, amount] of Object.entries(ores)) {
      const oreData = MINING_ORES[oreName];
      if (oreData) {
        totalValue += oreData.baseValue * amount;
      }
    }

    return totalValue;
  } catch (error) {
    logger.error('Error calculating total ore value:', error);
    return 0;
  }
}

// Add mining rewards to user
async function addMiningRewards(userId, rewards) {
  try {
    const user = await getUser(userId);
    if (!user) return false;

    const updateData = {};

    // Add coins
    if (rewards.coins) {
      updateData.coins = (user.coins || 0) + rewards.coins;
    }

    // Add XP
    if (rewards.xp) {
      updateData.goldMineXp = (user.goldMineXp || 0) + rewards.xp;
    }

    // Add ores to inventory
    if (rewards.ores && Object.keys(rewards.ores).length > 0) {
      if (!user.miningData) user.miningData = {};
      if (!user.miningData.inventory) user.miningData.inventory = {};

      Object.entries(rewards.ores).forEach(([ore, amount]) => {
        user.miningData.inventory[ore] = (user.miningData.inventory[ore] || 0) + amount;
      });

      updateData.miningData = user.miningData;
    }

    // Update user
    await safeUpdateUser(userId, updateData);
    return true;
  } catch (error) {
    console.error('Error adding mining rewards:', error);
    return false;
  }
}

// Team session management functions
async function createTeamSession(teamId, leaderId, teamName, maxMembers = 5) {
  try {
    const session = {
      teamId,
      leaderId,
      teamName,
      maxMembers,
      members: [leaderId],
      memberData: {
        [leaderId]: {
          joinedAt: Date.now(),
          contribution: 0
        }
      },
      createdAt: Date.now(),
      expiresAt: Date.now() + (30 * 60 * 1000), // 30 minutes
      activeEvents: [],
      teamBonus: 1.1, // Base 10% bonus
      status: 'active'
    };

    await safeUpdateUser(leaderId, {
      'mining.team.inTeam': true,
      'mining.team.teamId': teamId,
      'mining.team.teamStartTime': Date.now()
    });

    // Store session in memory (will be moved to database in future)
    if (!global.teamSessions) {
      global.teamSessions = new Map();
    }

    global.teamSessions.set(teamId, session);

    return session;
  } catch (error) {
    logger.error('Error creating team session:', error);
    return null;
  }
}

async function getTeamSession(teamId) {
  try {
    return global.teamSessions?.get(teamId) || null;
  } catch (error) {
    logger.error('Error getting team session:', error);
    return null;
  }
}

async function updateTeamSession(teamId, updates) {
  try {
    const session = global.teamSessions?.get(teamId);

    if (session) {
      Object.assign(session, updates);
      global.teamSessions.set(teamId, session);
      return true;
    }

    return false;
  } catch (error) {
    logger.error('Error updating team session:', error);
    return false;
  }
}

async function deleteTeamSession(teamId) {
  try {
    const session = global.teamSessions?.get(teamId);

    if (session) {
      // Update all team members
      for (const memberId of session.members) {
        await safeUpdateUser(memberId, {
          'mining.team.inTeam': false,
          'mining.team.teamId': null,
          'mining.team.teamStartTime': null
        });
      }

      global.teamSessions.delete(teamId);
      return true;
    }

    return false;
  } catch (error) {
    logger.error('Error deleting team session:', error);
    return false;
  }
}

async function getAllTeamSessions() {
  try {
    return Array.from(global.teamSessions?.values() || []);
  } catch (error) {
    logger.error('Error getting all team sessions:', error);
    return [];
  }
}

async function findUserTeamSession(userId) {
  try {
    const sessions = global.teamSessions || new Map();

    for (const [teamId, session] of sessions) {
      if (session.members.includes(userId)) {
        return { teamId, session };
      }
    }

    return null;
  } catch (error) {
    logger.error('Error finding user team session:', error);
    return null;
  }
}

async function cleanupExpiredTeamSessions() {
  try {
    const sessions = global.teamSessions || new Map();
    const now = Date.now();
    const expiredSessions = [];

    for (const [teamId, session] of sessions) {
      if (session.expiresAt < now) {
        expiredSessions.push(teamId);
      }
    }

    for (const teamId of expiredSessions) {
      await deleteTeamSession(teamId);
    }

    return expiredSessions.length;
  } catch (error) {
    logger.error('Error cleaning up expired team sessions:', error);
    return 0;
  }
}

module.exports = {
  initializeMiningData,
  getMiningData,
  updateMiningData,
  addOre,
  removeOre,
  addMiningXP,
  updateMiningStreak,
  updateQuestProgress,
  completeQuest,
  addTool,
  setCurrentTool,

  getOreInventory,
  getTotalOreValue,
  addMiningRewards,

  createTeamSession,
  getTeamSession,
  updateTeamSession,
  deleteTeamSession,
  getAllTeamSessions,
  findUserTeamSession,
  cleanupExpiredTeamSessions
};

const { EmbedBuilder } = require('discord.js');
const { getUser, safeUpdateUser } = require('../../../utils/database.js');
const { buildEmbed } = require('../../../utils/embeds.js');
const { getCurrentMineLevelXp } = require('../../../utils/utils.js');
