async function handleCollect(interaction) {
  try {
    const userId = interaction.user.id;
    const now = Date.now();
    const sessionDuration = 12 * 60 * 60 * 1000; // 12 hours

    const user = await getUser(userId);
    if (!user) {
      const embed = buildEmbed({
        title: '❌ User Not Found',
        description: 'You need to create an account first. Try using `/daily` or `/balance`.',
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    // Check if mining session exists and is complete
    if (!user.goldMineStartedAt) {
      const embed = buildEmbed({
        title: '❌ No Active Mining Session',
        description: 'You need to start a mining session first!\n\nUse `/mine start` to begin mining.',
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    const timeElapsed = now - user.goldMineStartedAt.getTime();

    if (timeElapsed < sessionDuration) {
      const timeRemaining = sessionDuration - timeElapsed;
      const hours = Math.floor(timeRemaining / (60 * 60 * 1000));
      const minutes = Math.floor((timeRemaining % (60 * 60 * 1000)) / (60 * 1000));

      const embed = buildEmbed({
        title: '⏰ Mining Session Not Ready',
        description: `Your mining session isn't complete yet!\n\n**Time remaining:** ${hours}h ${minutes}m\n\nCome back when the session is finished.`,
        color: 0xffa500
      });
      return await interaction.reply({ embeds: [embed] });
