    const xpGain = xpPerLevel * mineLevel;

    // Calculate new level
    const currentXp = user.goldMineXp || 0;
    const newXp = currentXp + xpGain;
    const xpRequired = 100 + (50 * mineLevel);

    let levelUp = false;
    let newLevel = mineLevel;

    if (newXp >= xpRequired) {
      levelUp = true;
      newLevel = mineLevel + 1;
    }

    // Update user data
    const updateData = {
      coins: (user.coins || 0) + totalReward,
      goldMineXp: newXp,
      goldMineLevel: newLevel,
      goldMineStartedAt: null,
      goldMineLastClaimed: new Date(),
      goldMineTotalCoins: (user.goldMineTotalCoins || 0) + totalReward
    };

    await safeUpdateUser(userId, updateData);

    // Create embed
    const embed = new EmbedBuilder()
      .setTitle('💰 Mining Rewards Collected!')
      .setDescription(`You've successfully collected your mining rewards!`)
      .setColor(0x00ff88)
      .addFields(
        { name: '💰 Gold Earned', value: `${totalReward.toLocaleString()} coins`, inline: true },
        { name: '⛏️ XP Gained', value: `+${xpGain} XP`, inline: true },
        { name: '📊 Current Level', value: `${newLevel}`, inline: true }
      )
      .setFooter({ text: 'Mining sessions last 12 hours' });

    if (levelUp) {
      embed.addFields({
        name: '🎉 Level Up!',
        value: `Congratulations! You've reached mining level **${newLevel}**!`,
        inline: false
      });
    }

    // Track quest progress
    await progressQuests(userId, ['mine_collect'], interaction);

    await interaction.reply({ embeds: [embed] });

  } catch (error) {
    console.error('Mine collect error:', error);
    const embed = buildEmbed({
      title: '❌ Error',
      description: 'An error occurred while collecting your mining rewards.',
      color: 0xff6b6b
    });
    await interaction.reply({ embeds: [embed], ephemeral: true });
  }
}

module.exports = handleCollect;

