const { EmbedBuilder } = require('discord.js');
const { getUser, safeUpdateUser } = require('../../../utils/database.js');
const { buildEmbed } = require('../../../utils/embeds.js');

// Mining contract definitions
const MINING_CONTRACTS = {
  easy: [
    {
      id: 'coal_supply',
      name: 'Coal Supply Contract',
      description: 'Mine 100 coal for the local blacksmith',
      npc: 'Blacksmith Tom',
      requirements: { coal: 100 },
      reward: { coins: 800, xp: 150, reputation: 10 },
      timeLimit: 3600000, // 1 hour
      difficulty: 'easy'
    },
    {
      id: 'iron_delivery',
      name: 'Iron Delivery',
      description: 'Collect 50 iron ore for the village',
      npc: 'Village Elder',
      requirements: { 'Iron Ore': 50 },
      reward: { coins: 1200, xp: 200, reputation: 15 },
      timeLimit: 7200000, // 2 hours
      difficulty: 'easy'
    }
  ],
  medium: [
    {
      id: 'precious_metals',
      name: 'Precious Metals Hunt',
      description: 'Find gold and silver for the jeweler',
      npc: 'Jeweler Sarah',
      requirements: { 'Gold Ore': 20, 'Silver Ore': 30 },
      reward: { coins: 2500, xp: 400, reputation: 25 },
      timeLimit: 10800000, // 3 hours
      difficulty: 'medium'
    },
    {
      id: 'deep_mining',
      name: 'Deep Mining Expedition',
      description: 'Mine at deep depths for rare materials',
      npc: 'Mining Foreman',
      requirements: { deepMining: 10 },
      reward: { coins: 3000, xp: 500, reputation: 30 },
      timeLimit: 14400000, // 4 hours
      difficulty: 'medium'
    }
  ],
  hard: [
    {
      id: 'gem_collection',
      name: 'Gem Collection Mission',
      description: 'Collect rare gems for the royal treasury',
      npc: 'Royal Treasurer',
      requirements: { 'Diamond': 5, 'Emerald': 5, 'Ruby': 5 },
      reward: { coins: 8000, xp: 1000, reputation: 50, item: 'Royal Mining Badge' },
      timeLimit: 21600000, // 6 hours
      difficulty: 'hard'
    },
    {
      id: 'legendary_quest',
      name: 'Legendary Ore Hunt',
      description: 'Find the rarest materials in the world',
      npc: 'Ancient Sage',
      requirements: { 'Crystal Shard': 1, 'Mythril': 10, 'Adamantite': 10 },
      reward: { coins: 15000, xp: 2000, reputation: 100, item: 'Legendary Miner Title' },
      timeLimit: 43200000, // 12 hours
      difficulty: 'hard'
    }
  ]
};

// NPC reputation levels and benefits
const REPUTATION_LEVELS = {
  0: { name: 'Unknown', benefits: [] },
  50: { name: 'Trusted', benefits: ['5% bonus rewards'] },
  100: { name: 'Respected', benefits: ['10% bonus rewards', 'Access to medium contracts'] },
  200: { name: 'Honored', benefits: ['15% bonus rewards', 'Access to hard contracts'] },
  500: { name: 'Legendary', benefits: ['20% bonus rewards', 'Exclusive contracts', 'Special items'] }
};

async function handleContracts(interaction) {
  try {
    const userId = interaction.user.id;
    const action = interaction.options.getString('action') || 'view';

    const user = await getUser(userId);
    if (!user) {
      const embed = buildEmbed({
        title: '❌ User Not Found',
        description: 'You need to create an account first. Try using `/daily` or `/balance`.',
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    // Initialize mining data if not exists
    if (!user.miningData) {
      user.miningData = {
        contracts: {
          active: [],
          completed: [],
          reputation: 0,
          npcRelations: {}
        }
      };
    }

    switch (action) {
      case 'view':
        await handleViewContracts(interaction, user);
        break;
      case 'accept':
        await handleAcceptContract(interaction, user);
        break;
      case 'complete':
        await handleCompleteContract(interaction, user);
        break;
      default:
        const embed = buildEmbed({
          title: '❌ Invalid Action',
          description: 'Please use `view`, `accept`, or `complete`.',
          color: 0xff6b6b
        });
        await interaction.reply({ embeds: [embed], ephemeral: true });
    }

  } catch (error) {
    console.error('Mining contracts error:', error);
    const embed = buildEmbed({
      title: '❌ Error',
      description: 'An error occurred while processing your contract request.',
      color: 0xff6b6b
    });
    await interaction.reply({ embeds: [embed], ephemeral: true });
  }
}

async function handleViewContracts(interaction, user) {
  const embed = new EmbedBuilder()
    .setTitle('📋 Mining Contracts')
    .setDescription('Accept contracts from NPCs to earn rewards and reputation')
    .setColor(0x00ff88);

  // Reputation status
  const reputation = user.miningData.contracts.reputation || 0;
  const currentLevel = getReputationLevel(reputation);
  const nextLevel = getNextReputationLevel(reputation);

  embed.addFields({
    name: '⭐ Reputation Status',
    value: `**Level:** ${currentLevel.name} (${reputation} points)\n**Next Level:** ${nextLevel ? nextLevel.name + ` (${nextLevel.required} points)` : 'MAX'}\n**Benefits:** ${currentLevel.benefits.join(', ') || 'None'}`,
    inline: false
  });

  // Active contracts
  const activeContracts = user.miningData.contracts.active || [];
  if (activeContracts.length > 0) {
    const activeList = activeContracts.map(contract => {
      const contractData = findContractById(contract.id);
      const timeLeft = contract.expiresAt - Date.now();
      const hoursLeft = Math.floor(timeLeft / 3600000);
      const minutesLeft = Math.floor((timeLeft % 3600000) / 60000);

      return `**${contractData.name}** (${contractData.npc})\n${contractData.description}\n⏰ ${hoursLeft}h ${minutesLeft}m left`;
    }).join('\n\n');

    embed.addFields({
      name: '📋 Active Contracts',
      value: activeList,
      inline: false
    });
  }

  // Available contracts
  const availableContracts = getAvailableContracts(user);
  if (availableContracts.length > 0) {
    const availableList = availableContracts.slice(0, 3).map(contract => {
      return `**${contract.name}** (${contract.npc})\n${contract.description}\n💰 ${contract.reward.coins} coins, ⭐ ${contract.reward.reputation} rep`;
    }).join('\n\n');

    embed.addFields({
      name: '🎯 Available Contracts',
      value: availableList + (availableContracts.length > 3 ? '\n\n*... and more*' : ''),
      inline: false
    });
  }

  // Completed contracts
  const completedCount = user.miningData.contracts.completed.length;
  embed.addFields({
    name: '🏆 Completed Contracts',
    value: `${completedCount} contracts completed`,
    inline: true
  });

  embed.setFooter({ text: 'Use /mine contracts accept to take on new contracts!' });

  await interaction.reply({ embeds: [embed] });
}

async function handleAcceptContract(interaction, user) {
  const contractId = interaction.options.getString('contract') || 'random';

  let contractToAccept;

  if (contractId === 'random') {
    const availableContracts = getAvailableContracts(user);
    if (availableContracts.length === 0) {
      const embed = buildEmbed({
        title: '❌ No Available Contracts',
        description: 'No contracts are available for your reputation level. Complete more contracts to unlock new ones!',
        color: 0xffa500
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    contractToAccept = availableContracts[Math.floor(Math.random() * availableContracts.length)];
  } else {
    contractToAccept = findContractById(contractId);
    if (!contractToAccept) {
      const embed = buildEmbed({
        title: '❌ Contract Not Found',
        description: 'The specified contract was not found.',
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }
  }

  // Check if user can accept this contract
  const reputation = user.miningData.contracts.reputation || 0;
  const canAccept = canAcceptContract(contractToAccept, reputation);

  if (!canAccept) {
    const embed = buildEmbed({
      title: '❌ Contract Locked',
      description: `You need ${getRequiredReputation(contractToAccept.difficulty)} reputation to accept ${contractToAccept.difficulty} contracts.`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  // Check if already have this contract
  const hasContract = user.miningData.contracts.active.find(c => c.id === contractToAccept.id);
  if (hasContract) {
    const embed = buildEmbed({
      title: '❌ Contract Already Active',
      description: `You already have the "${contractToAccept.name}" contract active.`,
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  // Accept contract
  const activeContract = {
    id: contractToAccept.id,
    acceptedAt: Date.now(),
    expiresAt: Date.now() + contractToAccept.timeLimit,
    progress: {}
  };

  user.miningData.contracts.active.push(activeContract);

  await safeUpdateUser(interaction.user.id, { miningData: user.miningData });

  const embed = buildEmbed({
    title: '✅ Contract Accepted!',
    description: `**${contractToAccept.name}**\n${contractToAccept.description}\n\n**NPC:** ${contractToAccept.npc}\n**Reward:** ${contractToAccept.reward.coins} coins, ${contractToAccept.reward.xp} XP, ${contractToAccept.reward.reputation} reputation\n**Time Limit:** ${Math.floor(contractToAccept.timeLimit / 3600000)} hours`,
    color: 0x00ff88,
    footer: { text: 'Use /mine contracts view to track your progress!' }
  });

  await interaction.reply({ embeds: [embed] });
}

async function handleCompleteContract(interaction, user) {
  const activeContracts = user.miningData.contracts.active || [];

  if (activeContracts.length === 0) {
    const embed = buildEmbed({
      title: '❌ No Active Contracts',
      description: 'You don\'t have any active contracts to complete.',
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const completedContracts = [];
  let totalCoins = 0;
  let totalXp = 0;
  let totalReputation = 0;
  const earnedItems = [];

  for (const contract of activeContracts) {
    const contractData = findContractById(contract.id);
    if (!contractData) continue;

    // Check if contract is completed
    const isCompleted = checkContractCompletion(contractData, user);

    if (isCompleted) {
      completedContracts.push(contractData);
      totalCoins += contractData.reward.coins;
      totalXp += contractData.reward.xp;
      totalReputation += contractData.reward.reputation;

      if (contractData.reward.item) {
        earnedItems.push(contractData.reward.item);
      }
    }
  }

  if (completedContracts.length === 0) {
    const embed = buildEmbed({
      title: '❌ No Contracts Ready',
      description: 'None of your active contracts are ready to complete. Keep mining to make progress!',
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  // Remove completed contracts and add to completed list
  const contractIds = completedContracts.map(c => c.id);
  user.miningData.contracts.active = user.miningData.contracts.active.filter(c => !contractIds.includes(c.id));
  user.miningData.contracts.completed.push(...contractIds);

  // Update reputation
  user.miningData.contracts.reputation = (user.miningData.contracts.reputation || 0) + totalReputation;

  // Update user data
  const updateData = {
    coins: (user.coins || 0) + totalCoins,
    goldMineXp: (user.goldMineXp || 0) + totalXp,
    miningData: user.miningData
  };

  await safeUpdateUser(interaction.user.id, updateData);

  const embed = buildEmbed({
    title: '🎉 Contracts Completed!',
    description: `**Completed:** ${completedContracts.map(c => c.name).join(', ')}\n\n**Rewards:**\n💰 ${totalCoins.toLocaleString()} coins\n⛏️ ${totalXp} mining XP\n⭐ ${totalReputation} reputation${earnedItems.length > 0 ? `\n🎁 Items: ${earnedItems.join(', ')}` : ''}`,
    color: 0x00ff88,
    footer: { text: 'Great work! Your reputation has increased!' }
  });

  await interaction.reply({ embeds: [embed] });
}

// Helper functions
function getAvailableContracts(user) {
  const reputation = user.miningData.contracts.reputation || 0;
  const activeContractIds = user.miningData.contracts.active.map(c => c.id);

  const available = [];

  Object.values(MINING_CONTRACTS).flat().forEach(contract => {
    if (!activeContractIds.includes(contract.id) && canAcceptContract(contract, reputation)) {
      available.push(contract);
    }
  });

  return available;
}

function canAcceptContract(contract, reputation) {
  const requiredRep = getRequiredReputation(contract.difficulty);
  return reputation >= requiredRep;
}

function getRequiredReputation(difficulty) {
  switch (difficulty) {
    case 'easy': return 0;
    case 'medium': return 100;
    case 'hard': return 200;
    default: return 0;
  }
}

function findContractById(id) {
  return Object.values(MINING_CONTRACTS).flat().find(c => c.id === id);
}

function getReputationLevel(reputation) {
  const levels = Object.keys(REPUTATION_LEVELS).map(Number).sort((a, b) => b - a);

  for (const level of levels) {
    if (reputation >= level) {
      return { ...REPUTATION_LEVELS[level], required: level };
    }
  }

  return { ...REPUTATION_LEVELS[0], required: 0 };
}

function getNextReputationLevel(reputation) {
  const levels = Object.keys(REPUTATION_LEVELS).map(Number).sort((a, b) => a - b);

  for (const level of levels) {
    if (reputation < level) {
      return { ...REPUTATION_LEVELS[level], required: level };
    }
  }

  return null;
}

function checkContractCompletion(contractData, user) {
  // This is a simplified check - in a real implementation, you'd track actual progress
  // For now, we'll simulate completion based on user's mining data

  const userOres = user.miningData.inventory || {};

  for (const [ore, required] of Object.entries(contractData.requirements)) {
    if (ore === 'deepMining') {
      // Check if user has mined at deep depths
      const deepMiningCount = user.miningData.stats?.depthsMined?.deep || 0;
      if (deepMiningCount < required) return false;
    } else {
      // Check if user has enough of the required ore
      if ((userOres[ore] || 0) < required) return false;
    }
  }

  return true;
}

module.exports = handleContracts;

