const { EmbedBuilder } = require('discord.js');
const { getUser, safeUpdateUser } = require('../../../utils/database.js');
const { buildEmbed } = require('../../../utils/embeds.js');
const { inventory } = require('../../../utils/utils.js');
const { MINING_TOOLS } = require('../constants.js');

// Equipment upgrade costs and effects
const EQUIPMENT_UPGRADES = {
  efficiency: {
    name: 'Efficiency',
    description: 'Increases mining speed and yield',
    baseCost: 1000,
    costMultiplier: 1.5,
    maxLevel: 10,
    effect: (level) => ({ speed: 1 + (level * 0.1), yield: 1 + (level * 0.05) })
  },
  durability: {
    name: 'Durability',
    description: 'Reduces tool wear and increases lifespan',
    baseCost: 800,
    costMultiplier: 1.3,
    maxLevel: 10,
    effect: (level) => ({ wear: 1 - (level * 0.08), lifespan: 1 + (level * 0.1) })
  },
  enchantment: {
    name: 'Enchantment',
    description: 'Adds magical properties to tools',
    baseCost: 2000,
    costMultiplier: 2.0,
    maxLevel: 5,
    effect: (level) => ({ luck: 1 + (level * 0.15), rareChance: level * 0.02 })
  },
  capacity: {
    name: 'Capacity',
    description: 'Increases ore storage capacity',
    baseCost: 1500,
    costMultiplier: 1.4,
    maxLevel: 8,
    effect: (level) => ({ storage: 1 + (level * 0.2) })
  }
};

// Tool repair costs
const REPAIR_COSTS = {
  'Wooden Pickaxe': 100,
  'Stone Pickaxe': 250,
  'Iron Pickaxe': 500,
  'Diamond Pickaxe': 1000,
  'Enchanted Shovel': 1500,
  'Mining Drill': 3000,
  'Explosive Charges': 5000
};

async function handleEquipment(interaction) {
  try {
    const userId = interaction.user.id;
    const action = interaction.options.getString('action') || 'view';

    const user = await getUser(userId);
    if (!user) {
      const embed = buildEmbed({
        title: '❌ User Not Found',
        description: 'You need to create an account first. Try using `/daily` or `/balance`.',
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    // Initialize mining data if not exists
    if (!user.miningData) {
      user.miningData = {
        equipment: {
          currentTool: 'Wooden Pickaxe',
          tools: ['Wooden Pickaxe'],
          upgrades: {
            efficiency: 0,
            durability: 0,
            enchantment: 0,
            capacity: 0
          },
          durability: {
            'Wooden Pickaxe': 100
          },
          enchantments: {}
        }
      };
    }

    switch (action) {
      case 'view':
        await handleViewEquipment(interaction, user);
        break;
      case 'upgrade':
        await handleUpgradeEquipment(interaction, user);
        break;
      case 'repair':
        await handleRepairEquipment(interaction, user);
        break;
      case 'enchant':
        await handleEnchantEquipment(interaction, user);
        break;
      default:
        const embed = buildEmbed({
          title: '❌ Invalid Action',
          description: 'Please use `view`, `upgrade`, `repair`, or `enchant`.',
          color: 0xff6b6b
        });
        await interaction.reply({ embeds: [embed], ephemeral: true });
    }

  } catch (error) {
    console.error('Mining equipment error:', error);
    const embed = buildEmbed({
      title: '❌ Error',
      description: 'An error occurred while processing your equipment request.',
      color: 0xff6b6b
    });
    await interaction.reply({ embeds: [embed], ephemeral: true });
  }
}

async function handleViewEquipment(interaction, user) {
  const embed = new EmbedBuilder()
    .setTitle('🛠️ Mining Equipment')
    .setDescription('Manage your mining tools and upgrades')
    .setColor(0x00ff88);

  // Current tool
  const currentTool = user.miningData.equipment.currentTool;
  const toolData = MINING_TOOLS[currentTool];
  const durability = user.miningData.equipment.durability[currentTool] || 100;

  embed.addFields({
    name: '⛏️ Current Tool',
    value: `**${currentTool}**\n${toolData.description}\nDurability: ${durability}%\nEfficiency: ${toolData.efficiency}x`,
    inline: false
  });

  // Owned tools
  const ownedTools = user.miningData.equipment.tools;
  if (ownedTools.length > 1) {
    const toolsList = ownedTools.map(tool => {
      const toolDurability = user.miningData.equipment.durability[tool] || 100;
      const status = toolDurability > 50 ? '🟢' : toolDurability > 20 ? '🟡' : '🔴';
      return `${status} ${tool} (${toolDurability}%)`;
    }).join('\n');

    embed.addFields({
      name: '📦 Owned Tools',
      value: toolsList,
      inline: false
    });
  }

  // Upgrades
  const upgrades = user.miningData.equipment.upgrades;
  const upgradesList = Object.entries(upgrades).map(([type, level]) => {
    const upgradeData = EQUIPMENT_UPGRADES[type];
    const nextCost = level < upgradeData.maxLevel ? 
      Math.floor(upgradeData.baseCost * Math.pow(upgradeData.costMultiplier, level)) : 'MAX';

    return `**${upgradeData.name}** (Level ${level}/${upgradeData.maxLevel})\n${upgradeData.description}\nNext: ${nextCost === 'MAX' ? 'MAXED' : nextCost + ' coins'}`;
  }).join('\n\n');

  embed.addFields({
    name: '⚡ Upgrades',
    value: upgradesList || 'No upgrades purchased',
    inline: false
  });

  // Enchantments
  const enchantments = user.miningData.equipment.enchantments;
  if (Object.keys(enchantments).length > 0) {
    const enchantList = Object.entries(enchantments).map(([tool, enchants]) => {
      return `**${tool}**: ${enchants.join(', ')}`;
    }).join('\n');

    embed.addFields({
      name: '🔮 Enchantments',
      value: enchantList,
      inline: false
    });
  }

  embed.setFooter({ text: 'Use /mine equipment upgrade to improve your tools!' });

  await interaction.reply({ embeds: [embed] });
}

async function handleUpgradeEquipment(interaction, user) {
  const upgradeType = interaction.options.getString('type') || 'efficiency';

  if (!EQUIPMENT_UPGRADES[upgradeType]) {
    const embed = buildEmbed({
      title: '❌ Invalid Upgrade Type',
      description: `Available types: ${Object.keys(EQUIPMENT_UPGRADES).join(', ')}`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const upgradeData = EQUIPMENT_UPGRADES[upgradeType];
  const currentLevel = user.miningData.equipment.upgrades[upgradeType] || 0;

  if (currentLevel >= upgradeData.maxLevel) {
    const embed = buildEmbed({
      title: '❌ Max Level Reached',
      description: `${upgradeData.name} is already at maximum level!`,
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const upgradeCost = Math.floor(upgradeData.baseCost * Math.pow(upgradeData.costMultiplier, currentLevel));

  if ((user.coins || 0) < upgradeCost) {
    const embed = buildEmbed({
      title: '❌ Insufficient Funds',
      description: `You need ${upgradeCost.toLocaleString()} coins to upgrade ${upgradeData.name} to level ${currentLevel + 1}.`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  // Apply upgrade
  user.miningData.equipment.upgrades[upgradeType] = currentLevel + 1;

  const updateData = {
    coins: (user.coins || 0) - upgradeCost,
    miningData: user.miningData
  };

  await safeUpdateUser(interaction.user.id, updateData);

  const newLevel = currentLevel + 1;
  const effects = upgradeData.effect(newLevel);

  const embed = buildEmbed({
    title: '✅ Upgrade Successful!',
    description: `**${upgradeData.name}** upgraded to level ${newLevel}!\n\n**New Effects:**\n${Object.entries(effects).map(([key, value]) => `${key}: ${value.toFixed(2)}x`).join('\n')}`,
    color: 0x00ff88,
    footer: { text: `Cost: ${upgradeCost.toLocaleString()} coins` }
  });

  await interaction.reply({ embeds: [embed] });
}

async function handleRepairEquipment(interaction, user) {
  const toolToRepair = interaction.options.getString('tool') || user.miningData.equipment.currentTool;

  if (!user.miningData.equipment.tools.includes(toolToRepair)) {
    const embed = buildEmbed({
      title: '❌ Tool Not Owned',
      description: `You don't own a ${toolToRepair}.`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const currentDurability = user.miningData.equipment.durability[toolToRepair] || 100;

  if (currentDurability >= 100) {
    const embed = buildEmbed({
      title: '✅ Tool Already Repaired',
      description: `${toolToRepair} is already at full durability!`,
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const repairCost = REPAIR_COSTS[toolToRepair] || 100;
  const durabilityNeeded = 100 - currentDurability;
  const actualCost = Math.floor(repairCost * (durabilityNeeded / 100));

  if ((user.coins || 0) < actualCost) {
    const embed = buildEmbed({
      title: '❌ Insufficient Funds',
      description: `You need ${actualCost.toLocaleString()} coins to repair ${toolToRepair}.`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  // Repair tool
  user.miningData.equipment.durability[toolToRepair] = 100;

  const updateData = {
    coins: (user.coins || 0) - actualCost,
    miningData: user.miningData
  };

  await safeUpdateUser(interaction.user.id, updateData);

  const embed = buildEmbed({
    title: '🔧 Tool Repaired!',
    description: `**${toolToRepair}** has been fully repaired!\n\nDurability: ${currentDurability}% → 100%`,
    color: 0x00ff88,
    footer: { text: `Cost: ${actualCost.toLocaleString()} coins` }
  });

  await interaction.reply({ embeds: [embed] });
}

async function handleEnchantEquipment(interaction, user) {
  const toolToEnchant = interaction.options.getString('tool') || user.miningData.equipment.currentTool;
  const enchantmentType = interaction.options.getString('enchantment') || 'luck';

  if (!user.miningData.equipment.tools.includes(toolToEnchant)) {
    const embed = buildEmbed({
      title: '❌ Tool Not Owned',
      description: `You don't own a ${toolToEnchant}.`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const enchantmentCosts = {
    luck: 5000,
    efficiency: 7500,
    durability: 3000,
    rare_finder: 10000
  };

  const enchantmentNames = {
    luck: 'Luck',
    efficiency: 'Efficiency',
    durability: 'Durability',
    rare_finder: 'Rare Finder'
  };

  if (!enchantmentCosts[enchantmentType]) {
    const embed = buildEmbed({
      title: '❌ Invalid Enchantment',
      description: `Available enchantments: ${Object.keys(enchantmentNames).join(', ')}`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const enchantmentCost = enchantmentCosts[enchantmentType];

  if ((user.coins || 0) < enchantmentCost) {
    const embed = buildEmbed({
      title: '❌ Insufficient Funds',
      description: `You need ${enchantmentCost.toLocaleString()} coins to enchant ${toolToEnchant} with ${enchantmentNames[enchantmentType]}.`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  // Apply enchantment
  if (!user.miningData.equipment.enchantments[toolToEnchant]) {
    user.miningData.equipment.enchantments[toolToEnchant] = [];
  }

  if (user.miningData.equipment.enchantments[toolToEnchant].includes(enchantmentNames[enchantmentType])) {
    const embed = buildEmbed({
      title: '❌ Already Enchanted',
      description: `${toolToEnchant} already has the ${enchantmentNames[enchantmentType]} enchantment!`,
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  user.miningData.equipment.enchantments[toolToEnchant].push(enchantmentNames[enchantmentType]);

  const updateData = {
    coins: (user.coins || 0) - enchantmentCost,
    miningData: user.miningData
  };

  await safeUpdateUser(interaction.user.id, updateData);

  const embed = buildEmbed({
    title: '🔮 Tool Enchanted!',
    description: `**${toolToEnchant}** has been enchanted with **${enchantmentNames[enchantmentType]}**!\n\nThis enchantment will improve your mining results.`,
    color: 0x00ff88,
    footer: { text: `Cost: ${enchantmentCost.toLocaleString()} coins` }
  });

  await interaction.reply({ embeds: [embed] });
}

module.exports = handleEquipment;

