const { EmbedBuilder } = require('discord.js');
const { getUser, safeUpdateUser } = require('../../../utils/database.js');
const { buildEmbed } = require('../../../utils/embeds.js');

// Investment opportunities
const INVESTMENT_OPPORTUNITIES = {
  stocks: {
    'MiningCorp': {
      name: 'Mining Corporation',
      description: 'Major mining company stock',
      basePrice: 100,
      volatility: 0.4,
      trend: 'bullish',
      dividend: 0.05 // 5% dividend
    },
    'ToolTech': {
      name: 'Tool Technology Inc',
      description: 'Advanced mining equipment manufacturer',
      basePrice: 150,
      volatility: 0.6,
      trend: 'rising',
      dividend: 0.03 // 3% dividend
    },
    'OreExchange': {
      name: 'Ore Exchange Market',
      description: 'Ore trading platform',
      basePrice: 200,
      volatility: 0.5,
      trend: 'stable',
      dividend: 0.04 // 4% dividend
    },
    'DeepMine': {
      name: 'Deep Mining Ventures',
      description: 'Deep mining exploration company',
      basePrice: 300,
      volatility: 0.8,
      trend: 'volatile',
      dividend: 0.08 // 8% dividend
    }
  },
  commodities: {
    'Iron_Futures': {
      name: 'Iron Ore Futures',
      description: 'Iron ore price speculation',
      basePrice: 50,
      volatility: 0.7,
      trend: 'rising'
    },
    'Gold_Futures': {
      name: 'Gold Futures',
      description: 'Gold price speculation',
      basePrice: 100,
      volatility: 0.6,
      trend: 'bullish'
    },
    'Diamond_Futures': {
      name: 'Diamond Futures',
      description: 'Diamond price speculation',
      basePrice: 500,
      volatility: 1.0,
      trend: 'volatile'
    }
  }
};

// Market events that affect investments
const INVESTMENT_EVENTS = [
  { name: 'Market Rally', effect: 1.3, duration: 1800000, description: 'All stocks increased by 30%!' },
  { name: 'Market Crash', effect: 0.7, duration: 1200000, description: 'All stocks decreased by 30%!' },
  { name: 'Tech Boom', effect: 1.5, duration: 2400000, description: 'Technology stocks surged!' },
  { name: 'Commodity Boom', effect: 1.4, duration: 2000000, description: 'Commodity prices soared!' }
];

let currentInvestmentEvent = null;
let investmentEventEndTime = 0;

// Initialize investment event system
function initializeInvestmentEvents() {
  setInterval(() => {
    const now = Date.now();

    // End current event if expired
    if (currentInvestmentEvent && now > investmentEventEndTime) {
      currentInvestmentEvent = null;
      investmentEventEndTime = 0;
    }

    // Start new event randomly (3% chance every 10 minutes)
    if (!currentInvestmentEvent && Math.random() < 0.03) {
      const event = INVESTMENT_EVENTS[Math.floor(Math.random() * INVESTMENT_EVENTS.length)];
      currentInvestmentEvent = event;
      investmentEventEndTime = now + event.duration;
    }
  }, 600000); // Check every 10 minutes
}

// Get current investment prices
function getCurrentInvestmentPrices() {
  const prices = {};
  const now = Date.now();

  Object.entries(INVESTMENT_OPPORTUNITIES).forEach(([category, investments]) => {
    Object.entries(investments).forEach(([id, data]) => {
      let price = data.basePrice;

      // Apply market event effects
      if (currentInvestmentEvent) {
        if (currentInvestmentEvent.name === 'Tech Boom' && category === 'stocks' && id === 'ToolTech') {
          price *= currentInvestmentEvent.effect;
        } else if (currentInvestmentEvent.name === 'Commodity Boom' && category === 'commodities') {
          price *= currentInvestmentEvent.effect;
        } else if (currentInvestmentEvent.name === 'Market Rally' || currentInvestmentEvent.name === 'Market Crash') {
          price *= currentInvestmentEvent.effect;
        }
      }

      // Apply daily fluctuations
      const dailySeed = Math.floor(now / 86400000);
      const fluctuation = (Math.sin(dailySeed + id.charCodeAt(0)) * data.volatility + 1);
      price *= fluctuation;

      // Apply trend effects
      switch (data.trend) {
        case 'rising':
          price *= 1.1;
          break;
        case 'bullish':
          price *= 1.2;
          break;
        case 'volatile':
          price *= 0.8 + (Math.random() * 0.6);
          break;
      }

      prices[id] = Math.floor(price);
    });
  });

  return prices;
}

async function handleInvestments(interaction) {
  try {
    const userId = interaction.user.id;
    const action = interaction.options.getString('action') || 'view';

    const user = await getUser(userId);
    if (!user) {
      const embed = buildEmbed({
        title: '❌ User Not Found',
        description: 'You need to create an account first. Try using `/daily` or `/balance`.',
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    // Initialize mining data if not exists
    if (!user.miningData) {
      user.miningData = {
        investments: {
          portfolio: {},
          history: [],
          totalInvested: 0,
          totalValue: 0
        }
      };
    }

    switch (action) {
      case 'view':
        await handleViewInvestments(interaction, user);
        break;
      case 'buy':
        await handleBuyInvestment(interaction, user);
        break;
      case 'sell':
        await handleSellInvestment(interaction, user);
        break;
      case 'portfolio':
        await handleViewPortfolio(interaction, user);
        break;
      default:
        const embed = buildEmbed({
          title: '❌ Invalid Action',
          description: 'Please use `view`, `buy`, `sell`, or `portfolio`.',
          color: 0xff6b6b
        });
        await interaction.reply({ embeds: [embed], ephemeral: true });
    }

  } catch (error) {
    console.error('Mining investments error:', error);
    const embed = buildEmbed({
      title: '❌ Error',
      description: 'An error occurred while processing your investment request.',
      color: 0xff6b6b
    });
    await interaction.reply({ embeds: [embed], ephemeral: true });
  }
}

async function handleViewInvestments(interaction, user) {
  const prices = getCurrentInvestmentPrices();
  const embed = new EmbedBuilder()
    .setTitle('📈 Mining Investments')
    .setDescription('Invest in mining-related stocks and commodities')
    .setColor(0x00ff88);

  // Market status
  if (currentInvestmentEvent) {
    const timeLeft = Math.max(0, investmentEventEndTime - Date.now());
    const minutesLeft = Math.floor(timeLeft / 60000);

    embed.addFields({
      name: `📊 Market Event: ${currentInvestmentEvent.name}`,
      value: `${currentInvestmentEvent.description}\n⏰ Ends in ${minutesLeft} minutes`,
      inline: false
    });
  }

  // Stock prices
  const stockPrices = Object.entries(INVESTMENT_OPPORTUNITIES.stocks).map(([id, data]) => {
    const price = prices[id];
    const trend = data.trend;
    const trendEmoji = trend === 'bullish' ? '📈' : trend === 'rising' ? '↗️' : trend === 'volatile' ? '📊' : '➡️';
    return `${trendEmoji} **${data.name}**: ${price.toLocaleString()} coins (${(data.dividend * 100).toFixed(1)}% div)`;
  }).join('\n');

  embed.addFields({
    name: '📊 Stock Prices',
    value: stockPrices,
    inline: false
  });

  // Commodity prices
  const commodityPrices = Object.entries(INVESTMENT_OPPORTUNITIES.commodities).map(([id, data]) => {
    const price = prices[id];
    const trend = data.trend;
    const trendEmoji = trend === 'bullish' ? '📈' : trend === 'rising' ? '↗️' : trend === 'volatile' ? '📊' : '➡️';
    return `${trendEmoji} **${data.name}**: ${price.toLocaleString()} coins`;
  }).join('\n');

  embed.addFields({
    name: '💰 Commodity Prices',
    value: commodityPrices,
    inline: false
  });

  // Portfolio summary
  const portfolio = user.miningData.investments.portfolio || {};
  const totalValue = calculatePortfolioValue(portfolio, prices);
  const totalInvested = user.miningData.investments.totalInvested || 0;
  const profit = totalValue - totalInvested;
  const profitPercentage = totalInvested > 0 ? (profit / totalInvested) * 100 : 0;

  embed.addFields({
    name: '💼 Portfolio Summary',
    value: `**Total Value:** ${totalValue.toLocaleString()} coins\n**Total Invested:** ${totalInvested.toLocaleString()} coins\n**Profit/Loss:** ${profit >= 0 ? '+' : ''}${profit.toLocaleString()} coins (${profitPercentage >= 0 ? '+' : ''}${profitPercentage.toFixed(1)}%)`,
    inline: false
  });

  embed.setFooter({ text: 'Use /mine investments buy to start investing!' });

  await interaction.reply({ embeds: [embed] });
}

async function handleBuyInvestment(interaction, user) {
  const investmentId = interaction.options.getString('investment') || 'MiningCorp';
  const amount = interaction.options.getInteger('amount') || 1;

  const investmentData = findInvestmentById(investmentId);
  if (!investmentData) {
    const embed = buildEmbed({
      title: '❌ Invalid Investment',
      description: `Available investments: ${Object.keys(INVESTMENT_OPPORTUNITIES.stocks).concat(Object.keys(INVESTMENT_OPPORTUNITIES.commodities)).join(', ')}`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  if (amount <= 0 || amount > 1000) {
    const embed = buildEmbed({
      title: '❌ Invalid Amount',
      description: 'Amount must be between 1 and 1000.',
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const prices = getCurrentInvestmentPrices();
  const pricePerShare = prices[investmentId];
  const totalCost = pricePerShare * amount;

  if ((user.coins || 0) < totalCost) {
    const embed = buildEmbed({
      title: '❌ Insufficient Funds',
      description: `You need ${totalCost.toLocaleString()} coins to buy ${amount} shares of ${investmentData.name}.`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  // Complete purchase
  if (!user.miningData.investments.portfolio) {
    user.miningData.investments.portfolio = {};
  }

  if (!user.miningData.investments.portfolio[investmentId]) {
    user.miningData.investments.portfolio[investmentId] = {
      shares: 0,
      averagePrice: 0,
      totalInvested: 0
    };
  }

  const portfolio = user.miningData.investments.portfolio[investmentId];
  const newShares = portfolio.shares + amount;
  const newTotalInvested = portfolio.totalInvested + totalCost;
  const newAveragePrice = newTotalInvested / newShares;

  portfolio.shares = newShares;
  portfolio.averagePrice = newAveragePrice;
  portfolio.totalInvested = newTotalInvested;

  user.miningData.investments.totalInvested = (user.miningData.investments.totalInvested || 0) + totalCost;

  const updateData = {
    coins: (user.coins || 0) - totalCost,
    miningData: user.miningData
  };

  await safeUpdateUser(interaction.user.id, updateData);

  const embed = buildEmbed({
    title: '✅ Investment Purchased!',
    description: `**${amount} shares** of ${investmentData.name} purchased for ${totalCost.toLocaleString()} coins\n\nPrice per share: ${pricePerShare.toLocaleString()} coins\nAverage price: ${newAveragePrice.toFixed(0)} coins`,
    color: 0x00ff88,
    footer: { text: 'Use /mine investments portfolio to track your investments!' }
  });

  await interaction.reply({ embeds: [embed] });
}

async function handleSellInvestment(interaction, user) {
  const investmentId = interaction.options.getString('investment') || 'all';
  const amount = interaction.options.getInteger('amount');

  if (!user.miningData.investments.portfolio || Object.keys(user.miningData.investments.portfolio).length === 0) {
    const embed = buildEmbed({
      title: '❌ No Investments to Sell',
      description: 'You don\'t have any investments in your portfolio.',
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const prices = getCurrentInvestmentPrices();
  let totalEarnings = 0;
  const soldInvestments = [];

  if (investmentId === 'all') {
    // Sell all investments
    Object.entries(user.miningData.investments.portfolio).forEach(([id, portfolio]) => {
      const price = prices[id] || 0;
      const earnings = price * portfolio.shares;
      totalEarnings += earnings;
      const investmentData = findInvestmentById(id);
      soldInvestments.push(`${portfolio.shares} shares of ${investmentData.name} (${earnings.toLocaleString()} coins)`);
    });

    user.miningData.investments.portfolio = {};
    user.miningData.investments.totalInvested = 0;
  } else {
    // Sell specific investment
    if (!user.miningData.investments.portfolio[investmentId]) {
      const embed = buildEmbed({
        title: '❌ Investment Not Found',
        description: `You don't have any shares of ${investmentId}.`,
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    const portfolio = user.miningData.investments.portfolio[investmentId];
    const sellAmount = amount || portfolio.shares;

    if (sellAmount > portfolio.shares) {
      const embed = buildEmbed({
        title: '❌ Insufficient Shares',
        description: `You only have ${portfolio.shares} shares of ${investmentId}.`,
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    const price = prices[investmentId] || 0;
    totalEarnings = price * sellAmount;
    const investmentData = findInvestmentById(investmentId);
    soldInvestments.push(`${sellAmount} shares of ${investmentData.name} (${totalEarnings.toLocaleString()} coins)`);

    portfolio.shares -= sellAmount;
    if (portfolio.shares <= 0) {
      delete user.miningData.investments.portfolio[investmentId];
    }

    user.miningData.investments.totalInvested -= (portfolio.averagePrice * sellAmount);
  }

  const updateData = {
    coins: (user.coins || 0) + totalEarnings,
    miningData: user.miningData
  };

  await safeUpdateUser(interaction.user.id, updateData);

  const embed = buildEmbed({
    title: '💰 Investment Sold!',
    description: `**Sold:**\n${soldInvestments.join('\n')}\n\n**Total Earnings:** ${totalEarnings.toLocaleString()} coins`,
    color: 0x00ff88,
    footer: { text: 'Great profit! Consider reinvesting for more gains!' }
  });

  await interaction.reply({ embeds: [embed] });
}

async function handleViewPortfolio(interaction, user) {
  const prices = getCurrentInvestmentPrices();
  const portfolio = user.miningData.investments.portfolio || {};

  if (Object.keys(portfolio).length === 0) {
    const embed = buildEmbed({
      title: '💼 Investment Portfolio',
      description: 'Your portfolio is empty. Start investing to see your holdings here!',
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const embed = new EmbedBuilder()
    .setTitle('💼 Investment Portfolio')
    .setDescription('Your current investment holdings and performance')
    .setColor(0x00ff88);

  let totalValue = 0;
  let totalInvested = 0;
  const holdings = [];

  Object.entries(portfolio).forEach(([id, holding]) => {
    const price = prices[id] || 0;
    const currentValue = price * holding.shares;
    const profit = currentValue - holding.totalInvested;
    const profitPercentage = (profit / holding.totalInvested) * 100;

    totalValue += currentValue;
    totalInvested += holding.totalInvested;

    const investmentData = findInvestmentById(id);
    const profitEmoji = profit >= 0 ? '📈' : '📉';

    holdings.push(`${profitEmoji} **${investmentData.name}**\nShares: ${holding.shares} | Value: ${currentValue.toLocaleString()} coins\nProfit: ${profit >= 0 ? '+' : ''}${profit.toLocaleString()} coins (${profitPercentage >= 0 ? '+' : ''}${profitPercentage.toFixed(1)}%)`);
  });

  embed.addFields({
    name: '📊 Holdings',
    value: holdings.join('\n\n'),
    inline: false
  });

  const totalProfit = totalValue - totalInvested;
  const totalProfitPercentage = totalInvested > 0 ? (totalProfit / totalInvested) * 100 : 0;

  embed.addFields({
    name: '💰 Portfolio Summary',
    value: `**Total Value:** ${totalValue.toLocaleString()} coins\n**Total Invested:** ${totalInvested.toLocaleString()} coins\n**Total Profit/Loss:** ${totalProfit >= 0 ? '+' : ''}${totalProfit.toLocaleString()} coins (${totalProfitPercentage >= 0 ? '+' : ''}${totalProfitPercentage.toFixed(1)}%)`,
    inline: false
  });

  embed.setFooter({ text: 'Prices update every hour | Use /mine investments sell to cash out' });

  await interaction.reply({ embeds: [embed] });
}

// Helper functions
function findInvestmentById(id) {
  return INVESTMENT_OPPORTUNITIES.stocks[id] || INVESTMENT_OPPORTUNITIES.commodities[id];
}

function calculatePortfolioValue(portfolio, prices) {
  return Object.entries(portfolio).reduce((total, [id, holding]) => {
    return total + ((prices[id] || 0) * holding.shares);
  }, 0);
}

// Initialize investment events when module loads
initializeInvestmentEvents();

module.exports = handleInvestments;

