const { EmbedBuilder } = require('discord.js');
const { getUser, safeUpdateUser } = require('../../../utils/database.js');
const { buildEmbed } = require('../../../utils/embeds.js');
const { MINING_ORES } = require('../constants.js');

// Market price ranges and volatility
const MARKET_DATA = {
  'Coal': { basePrice: 50, volatility: 0.3, trend: 'stable' },
  'Iron Ore': { basePrice: 100, volatility: 0.4, trend: 'rising' },
  'Copper Ore': { basePrice: 150, volatility: 0.5, trend: 'volatile' },
  'Gold Ore': { basePrice: 500, volatility: 0.6, trend: 'bullish' },
  'Silver Ore': { basePrice: 300, volatility: 0.5, trend: 'stable' },
  'Diamond': { basePrice: 2000, volatility: 0.8, trend: 'bullish' },
  'Emerald': { basePrice: 1800, volatility: 0.7, trend: 'rising' },
  'Ruby': { basePrice: 2200, volatility: 0.8, trend: 'volatile' },
  'Sapphire': { basePrice: 1900, volatility: 0.7, trend: 'stable' },
  'Mythril': { basePrice: 5000, volatility: 0.9, trend: 'bullish' },
  'Adamantite': { basePrice: 8000, volatility: 1.0, trend: 'bullish' },
  'Crystal Shard': { basePrice: 15000, volatility: 1.2, trend: 'volatile' }
};

// Market events that affect prices
const MARKET_EVENTS = [
  { name: 'Mining Boom', effect: 1.5, duration: 3600000, description: 'All ore prices increased by 50%!' },
  { name: 'Market Crash', effect: 0.7, duration: 1800000, description: 'All ore prices decreased by 30%!' },
  { name: 'Rare Ore Rush', effect: 2.0, duration: 2400000, description: 'Rare ore prices doubled!' },
  { name: 'Supply Surplus', effect: 0.8, duration: 1200000, description: 'Common ore prices decreased by 20%!' }
];

let currentMarketEvent = null;
let marketEventEndTime = 0;

// Initialize market event system
function initializeMarketEvents() {
  setInterval(() => {
    const now = Date.now();

    // End current event if expired
    if (currentMarketEvent && now > marketEventEndTime) {
      currentMarketEvent = null;
      marketEventEndTime = 0;
    }

    // Start new event randomly (5% chance every 5 minutes)
    if (!currentMarketEvent && Math.random() < 0.05) {
      const event = MARKET_EVENTS[Math.floor(Math.random() * MARKET_EVENTS.length)];
      currentMarketEvent = event;
      marketEventEndTime = now + event.duration;
    }
  }, 300000); // Check every 5 minutes
}

// Get current market prices with fluctuations
function getCurrentPrices() {
  const prices = {};
  const now = Date.now();

  Object.entries(MARKET_DATA).forEach(([ore, data]) => {
    let price = data.basePrice;

    // Apply market event effects
    if (currentMarketEvent) {
      if (currentMarketEvent.name === 'Rare Ore Rush' && isRareOre(ore)) {
        price *= currentMarketEvent.effect;
      } else if (currentMarketEvent.name === 'Supply Surplus' && !isRareOre(ore)) {
        price *= currentMarketEvent.effect;
      } else if (currentMarketEvent.name === 'Mining Boom' || currentMarketEvent.name === 'Market Crash') {
        price *= currentMarketEvent.effect;
      }
    }

    // Apply daily fluctuations
    const dailySeed = Math.floor(now / 86400000); // Daily seed
    const fluctuation = (Math.sin(dailySeed + ore.charCodeAt(0)) * data.volatility + 1);
    price *= fluctuation;

    // Apply trend effects
    switch (data.trend) {
      case 'rising':
        price *= 1.1;
        break;
      case 'bullish':
        price *= 1.2;
        break;
      case 'volatile':
        price *= 0.9 + (Math.random() * 0.4);
        break;
    }

    prices[ore] = Math.floor(price);
  });

  return prices;
}

function isRareOre(ore) {
  return ['Diamond', 'Emerald', 'Ruby', 'Sapphire', 'Mythril', 'Adamantite', 'Crystal Shard'].includes(ore);
}

async function handleMarket(interaction) {
  try {
    const userId = interaction.user.id;
    const action = interaction.options.getString('action') || 'view';

    const user = await getUser(userId);
    if (!user) {
      const embed = buildEmbed({
        title: '❌ User Not Found',
        description: 'You need to create an account first. Try using `/daily` or `/balance`.',
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    // Initialize mining data if not exists
    if (!user.miningData) {
      user.miningData = {
        inventory: {},
        marketHistory: []
      };
    }

    switch (action) {
      case 'view':
        await handleViewMarket(interaction, user);
        break;
      case 'buy':
        await handleBuyOres(interaction, user);
        break;
      case 'sell':
        await handleSellOres(interaction, user);
        break;
      case 'prices':
        await handleViewPrices(interaction, user);
        break;
      default:
        const embed = buildEmbed({
          title: '❌ Invalid Action',
          description: 'Please use `view`, `buy`, `sell`, or `prices`.',
          color: 0xff6b6b
        });
        await interaction.reply({ embeds: [embed], ephemeral: true });
    }

  } catch (error) {
    console.error('Mining market error:', error);
    const embed = buildEmbed({
      title: '❌ Error',
      description: 'An error occurred while processing your market request.',
      color: 0xff6b6b
    });
    await interaction.reply({ embeds: [embed], ephemeral: true });
  }
}

async function handleViewMarket(interaction, user) {
  const prices = getCurrentPrices();
  const embed = new EmbedBuilder()
    .setTitle('🏪 Mining Market')
    .setDescription('Buy and sell ores at current market prices')
    .setColor(0x00ff88);

  // Market status
  if (currentMarketEvent) {
    const timeLeft = Math.max(0, marketEventEndTime - Date.now());
    const minutesLeft = Math.floor(timeLeft / 60000);

    embed.addFields({
      name: `📊 Market Event: ${currentMarketEvent.name}`,
      value: `${currentMarketEvent.description}\n⏰ Ends in ${minutesLeft} minutes`,
      inline: false
    });
  }

  // Top 5 ore prices
  const sortedPrices = Object.entries(prices)
    .sort(([,a], [,b]) => b - a)
    .slice(0, 5);

  const topPricesText = sortedPrices.map(([ore, price], index) => {
    const trend = MARKET_DATA[ore].trend;
    const trendEmoji = trend === 'bullish' ? '📈' : trend === 'rising' ? '↗️' : trend === 'volatile' ? '📊' : '➡️';
    return `${index + 1}. ${trendEmoji} **${ore}**: ${price.toLocaleString()} coins`;
  }).join('\n');

  embed.addFields({
    name: '💰 Top Ore Prices',
    value: topPricesText,
    inline: false
  });

  // User's ore inventory
  const userOres = user.miningData.inventory || {};
  const totalValue = Object.entries(userOres).reduce((sum, [ore, amount]) => {
    return sum + (amount * (prices[ore] || 0));
  }, 0);

  embed.addFields({
    name: '📦 Your Ore Inventory',
    value: `Total Value: ${totalValue.toLocaleString()} coins\nUse \`/mine market sell\` to sell your ores!`,
    inline: false
  });

  embed.setFooter({ text: 'Prices update every hour | Use /mine market prices for full price list' });

  await interaction.reply({ embeds: [embed] });
}

async function handleBuyOres(interaction, user) {
  const oreToBuy = interaction.options.getString('ore') || 'Coal';
  const amount = interaction.options.getInteger('amount') || 1;

  if (!MARKET_DATA[oreToBuy]) {
    const embed = buildEmbed({
      title: '❌ Invalid Ore',
      description: `Available ores: ${Object.keys(MARKET_DATA).join(', ')}`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  if (amount <= 0 || amount > 1000) {
    const embed = buildEmbed({
      title: '❌ Invalid Amount',
      description: 'Amount must be between 1 and 1000.',
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const prices = getCurrentPrices();
  const pricePerOre = prices[oreToBuy];
  const totalCost = pricePerOre * amount;

  if ((user.coins || 0) < totalCost) {
    const embed = buildEmbed({
      title: '❌ Insufficient Funds',
      description: `You need ${totalCost.toLocaleString()} coins to buy ${amount} ${oreToBuy}.`,
      color: 0xff6b6b
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  // Complete purchase
  if (!user.miningData.inventory) {
    user.miningData.inventory = {};
  }

  user.miningData.inventory[oreToBuy] = (user.miningData.inventory[oreToBuy] || 0) + amount;

  const updateData = {
    coins: (user.coins || 0) - totalCost,
    miningData: user.miningData
  };

  await safeUpdateUser(interaction.user.id, updateData);

  const embed = buildEmbed({
    title: '✅ Purchase Successful!',
    description: `**${amount} ${oreToBuy}** purchased for ${totalCost.toLocaleString()} coins\n\nPrice per ore: ${pricePerOre.toLocaleString()} coins`,
    color: 0x00ff88,
    footer: { text: 'Use /mine market sell to sell your ores later!' }
  });

  await interaction.reply({ embeds: [embed] });
}

async function handleSellOres(interaction, user) {
  const oreToSell = interaction.options.getString('ore') || 'all';
  const amount = interaction.options.getInteger('amount');

  if (!user.miningData.inventory || Object.keys(user.miningData.inventory).length === 0) {
    const embed = buildEmbed({
      title: '❌ No Ores to Sell',
      description: 'You don\'t have any ores in your inventory.',
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed], ephemeral: true });
  }

  const prices = getCurrentPrices();
  let totalEarnings = 0;
  const soldOres = [];

  if (oreToSell === 'all') {
    // Sell all ores
    Object.entries(user.miningData.inventory).forEach(([ore, oreAmount]) => {
      const price = prices[ore] || 0;
      const earnings = price * oreAmount;
      totalEarnings += earnings;
      soldOres.push(`${oreAmount} ${ore} (${earnings.toLocaleString()} coins)`);
    });

    user.miningData.inventory = {};
  } else {
    // Sell specific ore
    if (!user.miningData.inventory[oreToSell]) {
      const embed = buildEmbed({
        title: '❌ Ore Not Found',
        description: `You don't have any ${oreToSell} to sell.`,
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    const availableAmount = user.miningData.inventory[oreToSell];
    const sellAmount = amount || availableAmount;

    if (sellAmount > availableAmount) {
      const embed = buildEmbed({
        title: '❌ Insufficient Ore',
        description: `You only have ${availableAmount} ${oreToSell}.`,
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    const price = prices[oreToSell] || 0;
    totalEarnings = price * sellAmount;
    soldOres.push(`${sellAmount} ${oreToSell} (${totalEarnings.toLocaleString()} coins)`);

    user.miningData.inventory[oreToSell] -= sellAmount;
    if (user.miningData.inventory[oreToSell] <= 0) {
      delete user.miningData.inventory[oreToSell];
    }
  }

  const updateData = {
    coins: (user.coins || 0) + totalEarnings,
    miningData: user.miningData
  };

  await safeUpdateUser(interaction.user.id, updateData);

  const embed = buildEmbed({
    title: '💰 Sale Successful!',
    description: `**Sold:**\n${soldOres.join('\n')}\n\n**Total Earnings:** ${totalEarnings.toLocaleString()} coins`,
    color: 0x00ff88,
    footer: { text: 'Great profit! Keep mining for more ores!' }
  });

  await interaction.reply({ embeds: [embed] });
}

async function handleViewPrices(interaction, user) {
  const prices = getCurrentPrices();
  const embed = new EmbedBuilder()
    .setTitle('📊 Current Market Prices')
    .setDescription('All ore prices at current market rates')
    .setColor(0x00ff88);

  // Group ores by rarity
  const commonOres = ['Coal', 'Iron Ore', 'Copper Ore'];
  const uncommonOres = ['Gold Ore', 'Silver Ore'];
  const rareOres = ['Diamond', 'Emerald', 'Ruby', 'Sapphire'];
  const epicOres = ['Mythril', 'Adamantite'];
  const legendaryOres = ['Crystal Shard'];

  const createOreList = (ores) => {
    return ores.map(ore => {
      const price = prices[ore];
      const trend = MARKET_DATA[ore].trend;
      const trendEmoji = trend === 'bullish' ? '📈' : trend === 'rising' ? '↗️' : trend === 'volatile' ? '📊' : '➡️';
      return `${trendEmoji} **${ore}**: ${price.toLocaleString()} coins`;
    }).join('\n');
  };

  embed.addFields(
    { name: '🟢 Common Ores', value: createOreList(commonOres), inline: true },
    { name: '🟡 Uncommon Ores', value: createOreList(uncommonOres), inline: true },
    { name: '🔵 Rare Ores', value: createOreList(rareOres), inline: true },
    { name: '🟣 Epic Ores', value: createOreList(epicOres), inline: true },
    { name: '✨ Legendary Ores', value: createOreList(legendaryOres), inline: true }
  );

  // Market trends
  const trends = Object.entries(MARKET_DATA).reduce((acc, [ore, data]) => {
    if (!acc[data.trend]) acc[data.trend] = [];
    acc[data.trend].push(ore);
    return acc;
  }, {});

  const trendsText = Object.entries(trends).map(([trend, ores]) => {
    const trendEmoji = trend === 'bullish' ? '📈' : trend === 'rising' ? '↗️' : trend === 'volatile' ? '📊' : '➡️';
    return `${trendEmoji} **${trend}**: ${ores.join(', ')}`;
  }).join('\n');

  embed.addFields({
    name: '📈 Market Trends',
    value: trendsText,
    inline: false
  });

  embed.setFooter({ text: 'Prices update every hour | Market events can affect prices' });

  await interaction.reply({ embeds: [embed] });
}

// Initialize market events when module loads
initializeMarketEvents();

module.exports = handleMarket;

const { EmbedBuilder } = require('discord.js');
const { withSafeReply } = require('../../../utils/safeReply');
const { getUser, safeUpdateUser } = require('../../../utils/database');
const { performMining, getMiningEfficiency, getMiningLuck, getAvailableDepths } = require('../logic');
const { getMiningData, setCurrentTool } = require('../database');
const { MINING_TOOLS, MINING_ORES, MINING_DEPTHS } = require('../constants');
const { getSeasonalMiningEffects } = require('../seasons');
const logger = require('../../../logger');

module.exports = withSafeReply(async (interaction) => {
  const userId = interaction.user.id;
  const toolName = interaction.options.getString('tool');
  const depth = interaction.options.getString('depth') || 'surface';

  try {
    // Get user data
    let user = await getUser(userId);
    if (!user) {
      return await interaction.reply({
        content: '❌ User not found in database!',
        flags: 1 << 6
      });
    }

    // Initialize mining data if needed
    let miningData = user.mining;
    if (!miningData) {
      await safeUpdateUser(userId, {
        mining: {
          level: 1,
          xp: 0,
          totalOresMined: 0,
          totalCoinsEarned: 0,
          lastMined: null,
          currentTool: 'Wooden Pickaxe',
          tools: ['Wooden Pickaxe'],
          ores: {},
          upgrades: {
            efficiency: 0,
            luck: 0,
            depth: 0,
            capacity: 0
          },
          quests: {
            active: [],
            completed: [],
            progress: {}
          },

          team: {
            inTeam: false,
            teamId: null,
            teamStartTime: null
          },
          streaks: {
            current: 0,
            longest: 0,
            lastMined: null
          },
          stats: {
            oresMined: {},
            toolsUsed: {},
            depthsMined: {},
            rareFinds: 0,
            totalMiningTime: 0
          }
        }
      });
      miningData = (await getUser(userId)).mining;
    }

    // Determine tool to use
    let selectedTool = toolName || miningData.currentTool;

    // Validate tool
    if (!MINING_TOOLS[selectedTool]) {
      return await interaction.reply({
        content: `❌ Invalid tool: ${selectedTool}`,
        flags: 1 << 6
      });
    }

    // Check if user has the tool
    if (!miningData.tools.includes(selectedTool)) {
      return await interaction.reply({
        content: `❌ You don't have the ${selectedTool}!`,
        flags: 1 << 6
      });
    }

    // Validate depth
    if (!MINING_DEPTHS[depth]) {
      return await interaction.reply({
        content: `❌ Invalid depth: ${depth}`,
        flags: 1 << 6
      });
    }

    // Check if tool can mine at this depth
    const depthLevels = ['surface', 'shallow', 'deep', 'cavern'];
    const tool = MINING_TOOLS[selectedTool];
    const toolDepthIndex = depthLevels.indexOf(tool.maxDepth);
    const targetDepthIndex = depthLevels.indexOf(depth);

    if (targetDepthIndex > toolDepthIndex) {
      return await interaction.reply({
        content: `❌ Your ${selectedTool} cannot mine at ${depth} depth!`,
        flags: 1 << 6
      });
    }

    // Perform mining with upgrade effects
    const miningResult = await performMining(userId, selectedTool, depth);

    if (!miningResult.success) {
      if (miningResult.timeRemaining) {
        return await interaction.reply({
          content: `⏰ You need to wait ${miningResult.timeRemaining} seconds before mining again!`,
          flags: 1 << 6
        });
      }
      return await interaction.reply({
        content: `❌ ${miningResult.reason}`,
        flags: 1 << 6
      });
    }

    // Update current tool if changed
    if (toolName && toolName !== miningData.currentTool) {
      await setCurrentTool(userId, toolName);
    }

    // Get seasonal effects
    const seasonalEffects = getSeasonalMiningEffects();

    // Create embed
    const embed = new EmbedBuilder()
      .setColor('#FFD700')
      .setTitle('⛏️ Mining Complete!')
      .setDescription(`You used your ${tool.emoji} **${selectedTool}** to mine at ${MINING_DEPTHS[depth].emoji} **${MINING_DEPTHS[depth].name}** depth!`)
      .addFields(
        { 
          name: '💎 Ore Found', 
          value: `${miningResult.oreData.emoji} **${miningResult.oreFound}** (${miningResult.oreData.rarity})`, 
          inline: true 
        },
        { 
          name: '💰 Coins Earned', 
          value: `${miningResult.rewards.coins} coins`, 
          inline: true 
        },
        { 
          name: '⭐ XP Gained', 
          value: `${miningResult.rewards.xp} XP`, 
          inline: true 
        }
      )
      .setTimestamp();

    // Add seasonal info
    if (seasonalEffects.multiplier !== 1.0) {
      const bonusPercent = Math.round((seasonalEffects.multiplier - 1) * 100);
      embed.addFields({
        name: `${seasonalEffects.emoji} Seasonal Bonus`,
        value: `${seasonalEffects.name}: +${bonusPercent}% bonus`,
        inline: false
      });
    }



    // Add rare find notification
    if (miningResult.isRareFind) {
      embed.addFields({
        name: '✨ Rare Find!',
        value: `You found a rare ${miningResult.oreData.rarity} ore!`,
        inline: false
      });
      embed.setColor('#FF69B4'); // Pink for rare finds
    }

    // Add upgrade effects info if any are active
    const activeUpgrades = miningResult.upgrades ? Object.entries(miningResult.upgrades).filter(([, level]) => level > 0) : [];
    if (activeUpgrades.length > 0) {
      const upgradeEffects = activeUpgrades.map(([upgrade, level]) => {
        const upgradeNames = {
          'ore_yield': 'Ore Yield',
          'experience_boost': 'XP Boost',
          'tool_efficiency': 'Tool Efficiency',
          'rare_chance': 'Rare Chance',
          'luck_enhancement': 'Luck Enhancement',
          'crystal_affinity': 'Crystal Affinity',
          'legendary_sense': 'Legendary Sense'
        };
        return `• ${upgradeNames[upgrade] || upgrade}: Level ${level}`;
      }).join('\n');

      embed.addFields({
        name: '⚡ Active Upgrades',
        value: upgradeEffects,
        inline: false
      });
    }

    // Add streak info
    const updatedMiningData = await getMiningData(userId);
    if (updatedMiningData.streaks.current > 1) {
      embed.addFields({
        name: '🔥 Mining Streak',
        value: `${updatedMiningData.streaks.current} days in a row!`,
        inline: true
      });
    }

    // Add next mining info
    embed.addFields({
      name: '⏰ Next Mining',
      value: 'Available in 30 seconds',
      inline: true
    });

    return await interaction.reply({ embeds: [embed] });

  } catch (error) {
    logger.error('Mining command error:', error);
    return await interaction.reply({
      content: '❌ An error occurred while mining!',
      flags: 1 << 6
    });
  }
});

