const { EmbedBuilder } = require('discord.js');
const { getUser, safeUpdateUser } = require('../../../utils/database.js');
const { buildEmbed } = require('../../../utils/embeds.js');
const { progressQuests } = require('../../../utils/quests.js');

// Mining quest definitions
const MINING_QUESTS = {
  daily: {
    mine_blocks: {
      name: 'Block Miner',
      description: 'Mine 50 blocks',
      goal: 50,
      reward: { coins: 500, xp: 100 },
      type: 'blocks'
    },
    find_diamonds: {
      name: 'Diamond Hunter',
      description: 'Find 3 diamonds',
      goal: 3,
      reward: { coins: 1000, xp: 200 },
      type: 'diamonds'
    },
    mine_duration: {
      name: 'Endurance Miner',
      description: 'Mine for 10 minutes total',
      goal: 600, // 10 minutes in seconds
      reward: { coins: 750, xp: 150 },
      type: 'duration'
    },
    rare_ores: {
      name: 'Rare Ore Collector',
      description: 'Find 5 rare or epic ores',
      goal: 5,
      reward: { coins: 1200, xp: 250 },
      type: 'rare_ores'
    }
  },
  weekly: {
    mining_master: {
      name: 'Mining Master',
      description: 'Complete 20 mining sessions',
      goal: 20,
      reward: { coins: 5000, xp: 1000, item: 'Mining Master Badge' },
      type: 'sessions'
    },
    depth_explorer: {
      name: 'Depth Explorer',
      description: 'Mine at all 4 depths',
      goal: 4,
      reward: { coins: 3000, xp: 800 },
      type: 'depths'
    },
    tool_collector: {
      name: 'Tool Collector',
      description: 'Use 3 different mining tools',
      goal: 3,
      reward: { coins: 2500, xp: 600 },
      type: 'tools'
    }
  },
  special: {
    seasonal_miner: {
      name: 'Seasonal Miner',
      description: 'Mine during all 4 seasons',
      goal: 4,
      reward: { coins: 10000, xp: 2000, item: 'Seasonal Miner Trophy' },
      type: 'seasons',
      permanent: true
    }
  }
};

async function handleQuest(interaction) {
  try {
    const userId = interaction.user.id;
    const action = interaction.options.getString('action') || 'view';

    const user = await getUser(userId);
    if (!user) {
      const embed = buildEmbed({
        title: '❌ User Not Found',
        description: 'You need to create an account first. Try using `/daily` or `/balance`.',
        color: 0xff6b6b
      });
      return await interaction.reply({ embeds: [embed], ephemeral: true });
    }

    // Initialize mining data if not exists
    if (!user.miningData) {
      user.miningData = {
        quests: {
          active: [],
          completed: [],
          progress: {},
          lastDailyReset: null,
          lastWeeklyReset: null
        }
      };
    }

    switch (action) {
      case 'view':
        await handleViewQuests(interaction, user);
        break;
      case 'accept':
        await handleAcceptQuest(interaction, user);
        break;
      case 'complete':
        await handleCompleteQuest(interaction, user);
        break;
      case 'abandon':
        await handleAbandonQuest(interaction, user);
        break;
      default:
        const embed = buildEmbed({
          title: '❌ Invalid Action',
          description: 'Please use `view`, `accept`, `complete`, or `abandon`.',
          color: 0xff6b6b
        });
        await interaction.reply({ embeds: [embed], ephemeral: true });
    }

  } catch (error) {
    console.error('Mining quest error:', error);
    const embed = buildEmbed({
      title: '❌ Error',
      description: 'An error occurred while processing your quest request.',
      color: 0xff6b6b
    });
    await interaction.reply({ embeds: [embed], ephemeral: true });
  }
}

async function handleViewQuests(interaction, user) {
  const now = Date.now();
  const dailyReset = getDailyReset();
  const weeklyReset = getWeeklyReset();

  // Reset daily quests if needed
  if (!user.miningData.quests.lastDailyReset || user.miningData.quests.lastDailyReset < dailyReset) {
    user.miningData.quests.active = user.miningData.quests.active.filter(q => !MINING_QUESTS.daily[q.id]);
    user.miningData.quests.lastDailyReset = now;
  }

  // Reset weekly quests if needed
  if (!user.miningData.quests.lastWeeklyReset || user.miningData.quests.lastWeeklyReset < weeklyReset) {
    user.miningData.quests.active = user.miningData.quests.active.filter(q => !MINING_QUESTS.weekly[q.id]);
    user.miningData.quests.lastWeeklyReset = now;
  }

  // Generate new daily quests if none active
  if (user.miningData.quests.active.filter(q => MINING_QUESTS.daily[q.id]).length === 0) {
    const dailyQuests = Object.keys(MINING_QUESTS.daily);
    const randomDaily = dailyQuests[Math.floor(Math.random() * dailyQuests.length)];
    user.miningData.quests.active.push({
      id: randomDaily,
      progress: 0,
      acceptedAt: now
    });
  }

  // Generate new weekly quests if none active
  if (user.miningData.quests.active.filter(q => MINING_QUESTS.weekly[q.id]).length === 0) {
    const weeklyQuests = Object.keys(MINING_QUESTS.weekly);
    const randomWeekly = weeklyQuests[Math.floor(Math.random() * weeklyQuests.length)];
    user.miningData.quests.active.push({
      id: randomWeekly,
      progress: 0,
      acceptedAt: now
    });
  }

  await safeUpdateUser(interaction.user.id, { miningData: user.miningData });

  const embed = new EmbedBuilder()
    .setTitle('📋 Mining Quests')
    .setDescription('Complete quests to earn rewards and progress!')
    .setColor(0x00ff88);

  // Active quests
  if (user.miningData.quests.active.length > 0) {
    const activeQuestsText = user.miningData.quests.active.map(quest => {
      const questData = MINING_QUESTS.daily[quest.id] || MINING_QUESTS.weekly[quest.id] || MINING_QUESTS.special[quest.id];
      const progress = user.miningData.quests.progress[quest.id] || 0;
      const percentage = Math.min((progress / questData.goal) * 100, 100);
      const progressBar = createProgressBar(percentage);

      return `**${questData.name}**\n${questData.description}\n${progressBar} ${progress}/${questData.goal} (${Math.round(percentage)}%)\nReward: ${questData.reward.coins} coins, ${questData.reward.xp} XP`;
    }).join('\n\n');

    embed.addFields({
      name: '🎯 Active Quests',
      value: activeQuestsText,
      inline: false
    });
  }

  // Completed quests count
  const completedCount = user.miningData.quests.completed.length;
  embed.addFields({
    name: '🏆 Completed Quests',
    value: `${completedCount} quests completed`,
    inline: true
  });

  // Quest streak
  const streak = calculateQuestStreak(user.miningData.quests.completed);
  embed.addFields({
    name: '🔥 Quest Streak',
    value: `${streak} days`,
    inline: true
  });

  embed.setFooter({ text: 'Use /mine quest accept to take on new quests!' });

  await interaction.reply({ embeds: [embed] });
}

async function handleAcceptQuest(interaction, user) {
  const availableQuests = [];

  // Check for available daily quests
  Object.keys(MINING_QUESTS.daily).forEach(questId => {
    if (!user.miningData.quests.active.find(q => q.id === questId) &&
        !user.miningData.quests.completed.includes(questId)) {
      availableQuests.push({ id: questId, ...MINING_QUESTS.daily[questId] });
    }
  });

  // Check for available weekly quests
  Object.keys(MINING_QUESTS.weekly).forEach(questId => {
    if (!user.miningData.quests.active.find(q => q.id === questId) &&
        !user.miningData.quests.completed.includes(questId)) {
      availableQuests.push({ id: questId, ...MINING_QUESTS.weekly[questId] });
    }
  });

  if (availableQuests.length === 0) {
    const embed = buildEmbed({
      title: '❌ No Available Quests',
      description: 'All quests are either active or completed. Check back later!',
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed] });
  }

  // Accept a random quest
  const randomQuest = availableQuests[Math.floor(Math.random() * availableQuests.length)];

  user.miningData.quests.active.push({
    id: randomQuest.id,
    progress: 0,
    acceptedAt: Date.now()
  });

  await safeUpdateUser(interaction.user.id, { miningData: user.miningData });

  const embed = buildEmbed({
    title: '✅ Quest Accepted!',
    description: `**${randomQuest.name}**\n${randomQuest.description}\n\n**Goal:** ${randomQuest.goal}\n**Reward:** ${randomQuest.reward.coins} coins, ${randomQuest.reward.xp} XP`,
    color: 0x00ff88,
    footer: { text: 'Use /mine quest view to track your progress!' }
  });

  await interaction.reply({ embeds: [embed] });
}

async function handleCompleteQuest(interaction, user) {
  const completedQuests = [];

  for (const quest of user.miningData.quests.active) {
    const questData = MINING_QUESTS.daily[quest.id] || MINING_QUESTS.weekly[quest.id] || MINING_QUESTS.special[quest.id];
    const progress = user.miningData.quests.progress[quest.id] || 0;

    if (progress >= questData.goal) {
      completedQuests.push({ quest, questData, progress });
    }
  }

  if (completedQuests.length === 0) {
    const embed = buildEmbed({
      title: '❌ No Quests Ready',
      description: 'You don\'t have any quests ready to complete. Keep mining to make progress!',
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed] });
  }

  let totalCoins = 0;
  let totalXp = 0;
  const completedNames = [];

  for (const { quest, questData } of completedQuests) {
    totalCoins += questData.reward.coins;
    totalXp += questData.reward.xp;
    completedNames.push(questData.name);

    // Remove from active, add to completed
    user.miningData.quests.active = user.miningData.quests.active.filter(q => q.id !== quest.id);
    user.miningData.quests.completed.push(quest.id);
  }

  // Update user rewards
  const updateData = {
    coins: (user.coins || 0) + totalCoins,
    miningData: user.miningData
  };

  // Add XP to mining XP
  if (totalXp > 0) {
    updateData.goldMineXp = (user.goldMineXp || 0) + totalXp;
  }

  await safeUpdateUser(interaction.user.id, updateData);

  const embed = buildEmbed({
    title: '🎉 Quests Completed!',
    description: `**Completed:** ${completedNames.join(', ')}\n\n**Rewards:**\n💰 ${totalCoins.toLocaleString()} coins\n⛏️ ${totalXp} mining XP`,
    color: 0x00ff88,
    footer: { text: 'Great job! Keep mining to complete more quests!' }
  });

  await interaction.reply({ embeds: [embed] });
}

async function handleAbandonQuest(interaction, user) {
  if (user.miningData.quests.active.length === 0) {
    const embed = buildEmbed({
      title: '❌ No Active Quests',
      description: 'You don\'t have any active quests to abandon.',
      color: 0xffa500
    });
    return await interaction.reply({ embeds: [embed] });
  }

  // Remove all active quests
  const abandonedCount = user.miningData.quests.active.length;
  user.miningData.quests.active = [];

  await safeUpdateUser(interaction.user.id, { miningData: user.miningData });

  const embed = buildEmbed({
    title: '🗑️ Quests Abandoned',
    description: `You have abandoned ${abandonedCount} quest(s).\n\nNew quests will be available when you use \`/mine quest view\`.`,
    color: 0xffa500,
    footer: { text: 'You can always accept new quests later!' }
  });

  await interaction.reply({ embeds: [embed] });
}

// Helper functions
function getDailyReset() {
  const now = new Date();
  return new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
}

function getWeeklyReset() {
  const now = new Date();
  const dayOfWeek = now.getDay();
  const daysToMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
  return new Date(now.getFullYear(), now.getMonth(), now.getDate() - daysToMonday).getTime();
}

function createProgressBar(percentage) {
  const length = 10;
  const filled = Math.floor((percentage / 100) * length);
  return '█'.repeat(filled) + '░'.repeat(length - filled);
}

function calculateQuestStreak(completedQuests) {
  // Simple streak calculation - could be enhanced with timestamps
  return Math.min(completedQuests.length, 30); // Cap at 30 days
}

module.exports = handleQuest;

const { EmbedBuilder } = require('discord.js');
const { withSafeReply } = require('../../../utils/safeReply');
const { getMiningData, updateMiningData } = require('../database');
const { 
  createTeamSession, 
  getTeamSession, 
  updateTeamSession, 
  deleteTeamSession, 
  getAllTeamSessions, 
  findUserTeamSession,
  cleanupExpiredTeamSessions 
} = require('../database');

// Team mining configurations
const TEAM_CONFIG = {
  maxTeamSize: 5,
  baseTeamBonus: 1.1, // 10% bonus for being in a team
  perMemberBonus: 0.05, // 5% bonus per additional member
  maxTeamBonus: 1.4, // Maximum 40% team bonus
  sessionDuration: 1800000, // 30 minutes
  cooldown: 3600000 // 1 hour cooldown
};

// Team mining events
const TEAM_EVENTS = [
  {
    name: 'Team Synergy',
    description: 'Perfect teamwork increases mining efficiency',
    effect: 1.2,
    duration: 300000, // 5 minutes
    chance: 0.1
  },
  {
    name: 'Coordinated Strike',
    description: 'Team members coordinate for maximum yield',
    effect: 1.3,
    duration: 240000, // 4 minutes
    chance: 0.05
  },
  {
    name: 'Mining Rush',
    description: 'Team enters a mining frenzy',
    effect: 1.25,
    duration: 180000, // 3 minutes
    chance: 0.08
  }
];

module.exports = withSafeReply(async (interaction) => {
  const userId = interaction.user.id;
  const action = interaction.options.getString('action') || 'view';

  try {
    // Clean up expired sessions first
    await cleanupExpiredTeamSessions();

    const miningData = await getMiningData(userId);
    if (!miningData) {
      return await interaction.reply({
        content: '❌ No mining data found! Start mining with `/mine mine`',
        flags: 1 << 6
      });
    }

    switch (action) {
      case 'view':
        return await handleViewTeam(interaction, miningData);
      case 'start':
        return await handleCreateTeam(interaction, miningData);
      case 'join':
        return await handleJoinTeam(interaction, miningData);
      case 'leave':
        return await handleLeaveTeam(interaction, miningData);
      case 'status':
        return await handleTeamStatus(interaction, miningData);
      case 'end':
        return await handleEndTeam(interaction, miningData);
      default:
        return await interaction.reply({
          content: '❌ Invalid action. Use `view`, `start`, `join`, `leave`, `status`, or `end`.',
          flags: 1 << 6
        });
    }

  } catch (error) {
    console.error('Mining team error:', error);
    return await interaction.reply({
      content: '❌ An error occurred while processing your team request.',
      flags: 1 << 6
    });
  }
});

async function handleViewTeam(interaction, miningData) {
  const embed = new EmbedBuilder()
    .setTitle('👥 Team Mining')
    .setDescription('Mine together with your guild or friends for bonuses')
    .setColor(0x00ff88);

  // Check if user is in an active team session
  const userSession = await findUserTeamSession(interaction.user.id);

  if (userSession) {
    const { teamId, session } = userSession;
    const timeLeft = session.expiresAt - Date.now();
    const minutesLeft = Math.floor(timeLeft / 60000);

    embed.addFields({
      name: '🔄 Active Team Session',
      value: `**Team:** ${session.teamName}\n**Members:** ${session.members.length}/${session.maxMembers}\n**Leader:** <@${session.leaderId}>\n**Time Left:** ${minutesLeft} minutes\n**Team Bonus:** ${((session.teamBonus - 1) * 100).toFixed(1)}%`,
      inline: false
    });

    // Team members
    const membersList = session.members.map(memberId => {
      const member = session.memberData[memberId];
      return `• <@${memberId}> - ${member.contribution} blocks mined`;
    }).join('\n');

    embed.addFields({
      name: '👥 Team Members',
      value: membersList,
      inline: false
    });

    // Active team events
    if (session.activeEvents.length > 0) {
      const eventsList = session.activeEvents.map(event => {
        const timeLeft = event.expiresAt - Date.now();
        const minutesLeft = Math.floor(timeLeft / 60000);
        return `• ${event.name} (${minutesLeft}m left) - ${((event.effect - 1) * 100).toFixed(0)}% bonus`;
      }).join('\n');

      embed.addFields({
        name: '⚡ Active Events',
        value: eventsList,
        inline: false
      });
    }
  } else {
    // Available teams
    const allSessions = await getAllTeamSessions();
    const availableTeams = allSessions.filter(session => 
      session.members.length < session.maxMembers && 
      !session.members.includes(interaction.user.id) &&
      session.status === 'active'
    );

    if (availableTeams.length > 0) {
      const teamsList = availableTeams.map(session => {
        const timeLeft = session.expiresAt - Date.now();
        const minutesLeft = Math.floor(timeLeft / 60000);
        return `• **${session.teamName}** by <@${session.leaderId}>\n  Members: ${session.members.length}/${session.maxMembers} | Time: ${minutesLeft}m`;
      }).join('\n\n');

      embed.addFields({
        name: '🎯 Available Teams',
        value: teamsList,
        inline: false
      });
    } else {
      embed.addFields({
        name: '🎯 Available Teams',
        value: 'No teams are currently available. Create your own team!',
        inline: false
      });
    }
  }

  // Team statistics
  const teamStats = miningData.team || {};
  embed.addFields({
    name: '📊 Team Statistics',
    value: `**Total Team Sessions:** ${teamStats.sessions?.length || 0}\n**Total Team Mining:** ${(teamStats.totalTeamMining || 0).toLocaleString()} blocks\n**Team Bonuses Earned:** ${(teamStats.teamBonuses || 0).toLocaleString()} coins`,
    inline: false
  });

  embed.setFooter({ text: 'Use /mine team start to start a team session!' });

  return await interaction.reply({ embeds: [embed] });
}

async function handleCreateTeam(interaction, miningData) {
  // Check if user is already in a team
  const existingSession = await findUserTeamSession(interaction.user.id);
  if (existingSession) {
    return await interaction.reply({
      content: '❌ You are already in a team session. Leave your current team first.',
      flags: 1 << 6
    });
  }

  const teamName = interaction.options.getString('name') || `${interaction.user.username}'s Team`;
  const teamId = `team_${interaction.user.id}_${Date.now()}`;

  const session = await createTeamSession(teamId, interaction.user.id, teamName, TEAM_CONFIG.maxTeamSize);

  if (!session) {
    return await interaction.reply({
      content: '❌ Failed to create team session. Please try again.',
      flags: 1 << 6
    });
  }

  const embed = new EmbedBuilder()
    .setColor(0x00ff88)
    .setTitle('👥 Team Created!')
    .setDescription(`**${teamName}** has been created!\n\n**Leader:** <@${interaction.user.id}>\n**Max Members:** ${TEAM_CONFIG.maxTeamSize}\n**Duration:** 30 minutes\n**Team Bonus:** 10% base bonus`)
    .addFields({
      name: '📋 Team Info',
      value: [
        `**Team ID:** ${teamId}`,
        `**Created:** <t:${Math.floor(session.createdAt / 1000)}:R>`,
        `**Expires:** <t:${Math.floor(session.expiresAt / 1000)}:R>`,
        `**Members:** 1/${TEAM_CONFIG.maxTeamSize}`
      ].join('\n'),
      inline: false
    })
    .setFooter({ text: 'Other players can join with /mine team join' });

  return await interaction.reply({ embeds: [embed] });
}

async function handleJoinTeam(interaction, miningData) {
  // Check if user is already in a team
  const existingSession = await findUserTeamSession(interaction.user.id);
  if (existingSession) {
    return await interaction.reply({
      content: '❌ You are already in a team session. Leave your current team first.',
      flags: 1 << 6
    });
  }

  const teamId = interaction.options.getString('team_id');
  if (!teamId) {
    return await interaction.reply({
      content: '❌ Please provide a team ID to join.',
      flags: 1 << 6
    });
  }

  const session = await getTeamSession(teamId);
  if (!session) {
    return await interaction.reply({
      content: '❌ Team not found or has expired.',
      flags: 1 << 6
    });
  }

  if (session.members.length >= session.maxMembers) {
    return await interaction.reply({
      content: '❌ This team is full.',
      flags: 1 << 6
    });
  }

  if (session.members.includes(interaction.user.id)) {
    return await interaction.reply({
      content: '❌ You are already a member of this team.',
      flags: 1 << 6
    });
  }

  // Add user to team
  session.members.push(interaction.user.id);
  session.memberData[interaction.user.id] = {
    joinedAt: Date.now(),
    contribution: 0
  };

  // Update team bonus
  const memberBonus = Math.min(session.members.length * TEAM_CONFIG.perMemberBonus, TEAM_CONFIG.maxTeamBonus - TEAM_CONFIG.baseTeamBonus);
  session.teamBonus = TEAM_CONFIG.baseTeamBonus + memberBonus;

  await updateTeamSession(teamId, session);
  await updateMiningData(interaction.user.id, {
    ...miningData,
    team: {
      ...miningData.team,
      inTeam: true,
      teamId: teamId,
      teamStartTime: Date.now()
    }
  });

  const embed = new EmbedBuilder()
    .setColor(0x00ff88)
    .setTitle('👥 Joined Team!')
    .setDescription(`You've joined **${session.teamName}**!\n\n**Leader:** <@${session.leaderId}>\n**Members:** ${session.members.length}/${session.maxMembers}\n**Team Bonus:** ${((session.teamBonus - 1) * 100).toFixed(1)}%`)
    .setFooter({ text: 'Start mining to contribute to your team!' });

  return await interaction.reply({ embeds: [embed] });
}

async function handleLeaveTeam(interaction, miningData) {
  const userSession = await findUserTeamSession(interaction.user.id);
  if (!userSession) {
    return await interaction.reply({
      content: '❌ You are not in a team session.',
      flags: 1 << 6
    });
  }

  const { teamId, session } = userSession;

  // Remove user from team
  session.members = session.members.filter(id => id !== interaction.user.id);
  delete session.memberData[interaction.user.id];

  // Update team bonus
  const memberBonus = Math.min(session.members.length * TEAM_CONFIG.perMemberBonus, TEAM_CONFIG.maxTeamBonus - TEAM_CONFIG.baseTeamBonus);
  session.teamBonus = TEAM_CONFIG.baseTeamBonus + memberBonus;

  // If no members left, delete the session
  if (session.members.length === 0) {
    await deleteTeamSession(teamId);
  } else {
    await updateTeamSession(teamId, session);
  }

  await updateMiningData(interaction.user.id, {
    ...miningData,
    team: {
      ...miningData.team,
      inTeam: false,
      teamId: null,
      teamStartTime: null
    }
  });

  const embed = new EmbedBuilder()
    .setColor(0xffa500)
    .setTitle('👥 Left Team')
    .setDescription(`You've left **${session.teamName}**.\n\n**Remaining Members:** ${session.members.length}/${session.maxMembers}`);

  return await interaction.reply({ embeds: [embed] });
}

