const { EmbedBuilder } = require('discord.js');
const { withSafeReply } = require('../../../utils/safeReply');
const { getMiningData, updateMiningData } = require('../database');
const { getUser, safeUpdateUser } = require('../../../utils/database');
const { MINING_UPGRADES } = require('../constants');
const { atomicEconomyTransfer } = require('../../../utils/atomicOperations');
const { reply } = require('../../../utils/formatting');

// Upgrade categories and their descriptions
const UPGRADE_CATEGORIES = {
  core: {
    name: 'Core Skills',
    description: 'Basic mining improvements',
    color: 0x00ff88
  },
  advanced: {
    name: 'Advanced Techniques',
    description: 'Specialized mining abilities',
    color: 0x0088ff
  },
  legendary: {
    name: 'Legendary Powers',
    description: 'Rare and powerful abilities',
    color: 0xff8800
  }
};

module.exports = withSafeReply(async (interaction) => {
  const userId = interaction.user.id;
  const action = interaction.options.getString('action') || 'view';
  const upgradeType = interaction.options.getString('type');

  try {
    const miningData = await getMiningData(userId);
    if (!miningData) {
      return await reply(interaction, {
        content: '❌ No mining data found! Start mining with `/mine mine`',
        flags: 1 << 6
      });
    }

    // Get user data for balance validation
    const user = await getUser(userId);
    if (!user) {
      return await reply(interaction, {
        content: '❌ User not found in database!',
        flags: 1 << 6
      });
    }

    switch (action) {
      case 'view':
        return await handleViewUpgrades(interaction, miningData, user);
      case 'purchase':
        return await handlePurchaseUpgrade(interaction, miningData, user, upgradeType);
      case 'info':
        return await handleUpgradeInfo(interaction, miningData, user, upgradeType);
      default:
        return await reply(interaction, {
          content: '❌ Invalid action. Use `view`, `purchase`, or `info`.',
          flags: 1 << 6
        });
    }

  } catch (error) {
    console.error('Mining upgrade error:', error);
    return await reply(interaction, {
      content: '❌ An error occurred while processing your upgrade request.',
      flags: 1 << 6
    });
  }
});

async function handleViewUpgrades(interaction, miningData, user) {
  const embed = new EmbedBuilder()
    .setTitle('⚡ Mining Upgrades')
    .setDescription('Improve your mining abilities with permanent upgrades')
    .setColor(0x00ff88);

  // Current stats
  const stats = miningData.stats || {};
  const totalMined = stats.totalOresMined || 0;
  const depthsMined = Object.keys(stats.depthsMined || {}).length;

  embed.addFields({
    name: '📊 Mining Statistics',
    value: `**Total Blocks Mined:** ${totalMined.toLocaleString()}\n**Depths Explored:** ${depthsMined}\n**Upgrades Purchased:** ${Object.keys(miningData.upgrades || {}).length}`,
    inline: false
  });

  // User balance
  embed.addFields({
    name: '💰 Your Balance',
    value: `${(user.coins || 0).toLocaleString()} coins`,
    inline: true
  });

  // Upgrades by category
  Object.entries(UPGRADE_CATEGORIES).forEach(([categoryId, category]) => {
    const categoryUpgrades = Object.entries(MINING_UPGRADES)
      .filter(([, upgrade]) => upgrade.category === categoryId)
      .map(([id, upgrade]) => {
        const currentLevel = miningData.upgrades?.[id] || 0;
        const nextCost = currentLevel < upgrade.maxLevel ? 
          Math.floor(upgrade.baseCost * Math.pow(upgrade.costMultiplier, currentLevel)) : 'MAX';

        const canAfford = nextCost === 'MAX' || (user.coins || 0) >= nextCost;
        const status = nextCost === 'MAX' ? '✅ MAX' : canAfford ? '💰 Available' : '❌ Too Expensive';

        return `${upgrade.emoji || '⚡'} **${upgrade.name}** (Level ${currentLevel}/${upgrade.maxLevel})\n└ ${status}${nextCost !== 'MAX' ? ` - ${nextCost.toLocaleString()} coins` : ''}`;
      })
      .join('\n\n');

    if (categoryUpgrades) {
      embed.addFields({
        name: `${category.emoji || '📈'} ${category.name}`,
        value: categoryUpgrades,
        inline: false
      });
    }
  });

  embed.setFooter({ text: 'Use /mine upgrade purchase <type> to buy upgrades!' });

  return await reply(interaction, { embeds: [embed] });
}

async function handlePurchaseUpgrade(interaction, miningData, user, upgradeType) {
  if (!upgradeType) {
    return await reply(interaction, {
      content: `❌ Upgrade type required. Available upgrades: ${Object.keys(MINING_UPGRADES).join(', ')}`,
      flags: 1 << 6
    });
  }

  const upgradeData = MINING_UPGRADES[upgradeType];
  if (!upgradeData) {
    return await reply(interaction, {
      content: `❌ Invalid upgrade. Available upgrades: ${Object.keys(MINING_UPGRADES).join(', ')}`,
      flags: 1 << 6
    });
  }

  const currentLevel = miningData.upgrades?.[upgradeType] || 0;

  if (currentLevel >= upgradeData.maxLevel) {
    return await reply(interaction, {
      content: `❌ ${upgradeData.name} is already at maximum level!`,
      flags: 1 << 6
    });
  }

  const upgradeCost = Math.floor(upgradeData.baseCost * Math.pow(upgradeData.costMultiplier, currentLevel));
  const userBalance = user.coins || 0;

  // Validate balance with proper error handling
  if (userBalance < upgradeCost) {
    const shortfall = upgradeCost - userBalance;
    return await reply(interaction, {
      content: `❌ Insufficient funds! You need ${upgradeCost.toLocaleString()} coins but only have ${userBalance.toLocaleString()} coins.\n\nYou need ${shortfall.toLocaleString()} more coins.`,
      flags: 1 << 6
    });
  }

  // Validate that the cost won't result in negative balance
  if (userBalance - upgradeCost < 0) {
    return await reply(interaction, {
      content: '❌ Transaction would result in negative balance. Please try again.',
      flags: 1 << 6
    });
  }

  try {
    // Transaction-based update to prevent race conditions
    const newBalance = userBalance - upgradeCost;
    const newLevel = currentLevel + 1;
    // Use atomic operation for coins and upgrades
    await atomicEconomyTransfer(interaction.user.id, null, upgradeCost, 'mining_upgrade', {
      upgrades: {
        ...miningData.upgrades,
        [upgradeType]: newLevel
      }
    });
    const effects = upgradeData.effect(newLevel);

    const embed = new EmbedBuilder()
      .setColor(0x00ff88)
      .setTitle('✅ Upgrade Purchased!')
      .setDescription(`**${upgradeData.name}** upgraded to level ${newLevel}!\n\n**New Effects:**\n${Object.entries(effects).map(([key, value]) => {
        const effectNames = {
          speed: 'Mining Speed',
          yield: 'Ore Yield',
          rareChance: 'Rare Ore Chance',
          toolEfficiency: 'Tool Efficiency',
          xpMultiplier: 'XP Multiplier',
          luck: 'Luck',
          crystalChance: 'Crystal Chance',
          legendaryChance: 'Legendary Chance',
          maxDepth: 'Max Depth',
          autoCollect: 'Auto Collection'
        };

        if (key === 'autoCollect') {
          return `• ${effectNames[key]}: Enabled`;
        } else if (key.includes('Chance')) {
          return `• ${effectNames[key]}: +${(value * 100).toFixed(1)}%`;
        } else {
          return `• ${effectNames[key]}: ${value.toFixed(2)}x`;
        }
      }).join('\n')}`)
      .addFields(
        {
          name: '💰 Cost',
          value: `${upgradeCost.toLocaleString()} coins`,
          inline: true
        },
        {
          name: '💰 New Balance',
          value: `${newBalance.toLocaleString()} coins`,
          inline: true
        }
      );

    return await reply(interaction, { embeds: [embed] });

  } catch (error) {
    console.error('Error purchasing upgrade:', error);
    return await reply(interaction, {
      content: '❌ Failed to purchase upgrade. Please try again.',
      flags: 1 << 6
    });
  }
}

async function handleUpgradeInfo(interaction, miningData, user, upgradeType) {
  if (!upgradeType) {
    return await reply(interaction, {
      content: `❌ Upgrade type required. Available upgrades: ${Object.keys(MINING_UPGRADES).join(', ')}`,
      flags: 1 << 6
    });
  }

  const upgradeData = MINING_UPGRADES[upgradeType];
