  if (costProgression.length > 0) {
    embed.addFields({
      name: '💰 Cost Progression',
      value: costProgression.join('\n'),
      inline: false
    });
  }

  // Effect progression
  const effectProgression = [];
  for (let level = 1; level <= upgradeData.maxLevel; level += Math.ceil(upgradeData.maxLevel / 5)) {
    const effects = upgradeData.effect(level);
    const effectText = Object.entries(effects).map(([key, value]) => {
      const effectNames = {
        speed: 'Speed',
        yield: 'Yield',
        rareChance: 'Rare Chance',
        toolEfficiency: 'Tool Efficiency',
        xpMultiplier: 'XP Multiplier',
        luck: 'Luck',
        crystalChance: 'Crystal Chance',
        legendaryChance: 'Legendary Chance',
        maxDepth: 'Max Depth',
        autoCollect: 'Auto Collect'
      };

      if (key === 'autoCollect') {
        return `${effectNames[key]}: Enabled`;
      } else if (key.includes('Chance')) {
        return `${effectNames[key]}: +${(value * 100).toFixed(1)}%`;
      } else {
        return `${effectNames[key]}: ${value.toFixed(2)}x`;
      }
    }).join(', ');

    effectProgression.push(`Level ${level}: ${effectText}`);
  }

  embed.addFields({
    name: '✨ Effect Progression',
    value: effectProgression.join('\n'),
    inline: false
  });

  embed.setFooter({ text: `Use /mine upgrade purchase ${upgradeType} to buy this upgrade!` });

  return await reply(interaction, { embeds: [embed] });
}

