const { MINING_SEASONS } = require('./constants');
const logger = require('../../logger');

let client = null;

// Set Discord client for notifications
function setClient(discordClient) {
  client = discordClient;
}

// Get current mining season
function getCurrentMiningSeason() {
  try {
    const now = new Date();
    const month = now.getMonth() + 1; // getMonth() returns 0-11
    const day = now.getDate();

    // Spring: March 20 - June 20
    if ((month === 3 && day >= 20) || month === 4 || month === 5 || (month === 6 && day <= 20)) {
      return MINING_SEASONS.spring;
    }
    // Summer: June 21 - September 22
    else if ((month === 6 && day >= 21) || month === 7 || month === 8 || (month === 9 && day <= 22)) {
      return MINING_SEASONS.summer;
    }
    // Autumn: September 23 - December 20
    else if ((month === 9 && day >= 23) || month === 10 || month === 11 || (month === 12 && day <= 20)) {
      return MINING_SEASONS.autumn;
    }
    // Winter: December 21 - March 19
    else {
      return MINING_SEASONS.winter;
    }
  } catch (error) {
    logger.error('Error getting current mining season:', error);
    return MINING_SEASONS.spring; // Fallback
  }
}

// Get seasonal mining multiplier
function getSeasonalMiningMultiplier() {
  try {
    const season = getCurrentMiningSeason();
    return season.multiplier;
  } catch (error) {
    logger.error('Error getting seasonal mining multiplier:', error);
    return 1.0; // Fallback to no bonus
  }
}

// Get seasonal mining effects description
function getSeasonalMiningEffects() {
  try {
    const season = getCurrentMiningSeason();
    return {
      name: season.name,
      emoji: season.emoji,
      description: season.description,
      effects: season.effects,
      multiplier: season.multiplier
    };
  } catch (error) {
    logger.error('Error getting seasonal mining effects:', error);
    return {
      name: 'Spring',
      emoji: '🌸',
      description: 'Normal mining conditions',
      effects: ['Standard efficiency', 'Normal energy consumption'],
      multiplier: 1.0
    };
  }
}

// Get next season info
function getNextMiningSeason() {
  try {
    const currentSeason = getCurrentMiningSeason();
    const seasons = Object.values(MINING_SEASONS);
    const currentIndex = seasons.findIndex(s => s.name === currentSeason.name);
    const nextIndex = (currentIndex + 1) % seasons.length;

    return seasons[nextIndex];
  } catch (error) {
    logger.error('Error getting next mining season:', error);
    return MINING_SEASONS.spring;
  }
}

// Calculate days until next season
function getDaysUntilNextSeason() {
  try {
    const now = new Date();
    const currentSeason = getCurrentMiningSeason();
    const nextSeason = getNextMiningSeason();

    let nextSeasonDate;

    // Calculate next season start date
    switch (nextSeason.name.toLowerCase()) {
      case 'spring':
        nextSeasonDate = new Date(now.getFullYear(), 2, 20); // March 20
        break;
      case 'summer':
        nextSeasonDate = new Date(now.getFullYear(), 5, 21); // June 21
        break;
      case 'autumn':
        nextSeasonDate = new Date(now.getFullYear(), 8, 23); // September 23
        break;
      case 'winter':
        nextSeasonDate = new Date(now.getFullYear(), 11, 21); // December 21
        break;
      default:
        return 0;
    }

    // If next season date has passed this year, it's next year
    if (nextSeasonDate < now) {
      nextSeasonDate.setFullYear(now.getFullYear() + 1);
    }

    const timeDiff = nextSeasonDate.getTime() - now.getTime();
    const daysDiff = Math.ceil(timeDiff / (1000 * 3600 * 24));

    return daysDiff;
  } catch (error) {
    logger.error('Error calculating days until next season:', error);
    return 0;
  }
}

// Get seasonal mining tips
function getSeasonalMiningTips() {
  try {
    const season = getCurrentMiningSeason();

    const tips = {
