// Get seasonal multiplier for mining
function getSeasonalMultiplier(season) {
  const seasonData = MINING_SEASONS[season];
  if (!seasonData) return 1.0;

  return seasonData.multiplier || 1.0;
}

// Get current seasonal events
function getSeasonalEvents(season) {
  const seasonData = MINING_SEASONS[season];
  if (!seasonData) return [];

  return seasonData.events || [];
}

