        if (user.xp < 0) {
          await User.findByIdAndUpdate(userId, { $set: { xp: 0 } }, { session });
          user.xp = 0;
        }

        return user;
      }
    ], null, { context: 'economy_xp_update' });

    return { success: true, user: result[0] };
  } catch (error) {
