async function awardGuildExperience(guildId, experience, interaction = null) {
  let guild;
  try {
    guild = await Guild.findById(guildId);
  } catch (err) {
    logger.error('DB error in awardGuildExperience Guild.findById:', err);
    return;
  }
  if (!guild) return;

  const currentLevel = guild.level || 1;
  const currentExp = guild.experience || 0;
  const expNeededForNextLevel = currentLevel * 1000; // 1000 XP per level

  const newExp = currentExp + experience;
  let levelUp = false;
  let newLevel = currentLevel;

  // Check if guild leveled up
  if (newExp >= expNeededForNextLevel) {
    newLevel = currentLevel + 1;
    levelUp = true;
  }
  try {
    await Guild.findByIdAndUpdate(guildId, {
      experience: newExp,
      level: newLevel
    });
  } catch (err) {
    logger.error('DB error in awardGuildExperience Guild.findByIdAndUpdate:', err);
    return;
  }
  if (levelUp && interaction) {
    try {
      if (!isSafeDiscordId(interaction.user.id)) {
        return await reply(interaction, 'Invalid user ID.', { flags: 1 << 6 });
      }
      await withSafeReply(async (interaction) => {
        // ... original command logic, minus manual pre-checks ...
      })(interaction);
    } catch (err) {
      logger.error('Discord API error in awardGuildExperience level up reply:', err);
    }
  }
  progressQuests(interaction?.user?.id, ['guild_core'], interaction).catch(e => logger.error('progressQuests error:', e));
  return { levelUp, newLevel, newExp };
}

