/**
 * Race Condition Protection Utility
 * Prevents race conditions in competitive features
 */

const logger = require('../logger');

class RaceConditionProtection {
  constructor() {
    this.locks = new Map();
    this.timeouts = new Map();
    this.defaultTimeout = 30000; // 30 seconds
  }

  /**
   * Acquire a lock for a specific resource
   */
  async acquireLock(resourceId, timeout = this.defaultTimeout) {
    const lockKey = `lock:${resourceId}`;

    // Check if lock already exists
    if (this.locks.has(lockKey)) {
      const lock = this.locks.get(lockKey);
      const now = Date.now();

      // If lock is expired, remove it
      if (now > lock.expiresAt) {
        this.releaseLock(resourceId);
      } else {
        throw new Error(`Resource ${resourceId} is currently locked`);
      }
    }

    // Create new lock
    const lock = {
      resourceId,
      acquiredAt: Date.now(),
      expiresAt: Date.now() + timeout,
      timeoutId: setTimeout(() => {
        this.releaseLock(resourceId);
      }, timeout)
    };

    this.locks.set(lockKey, lock);
    logger.debug(`Lock acquired for resource: ${resourceId}`);

    return lock;
  }

  /**
   * Release a lock
   */
  releaseLock(resourceId) {
    const lockKey = `lock:${resourceId}`;
    const lock = this.locks.get(lockKey);

    if (lock) {
      clearTimeout(lock.timeoutId);
      this.locks.delete(lockKey);
      logger.debug(`Lock released for resource: ${resourceId}`);
    }
  }

  /**
   * Execute function with resource locking
   */
  async withLock(resourceId, operation, timeout = this.defaultTimeout) {
    let lock = null;

    try {
      lock = await this.acquireLock(resourceId, timeout);
      const result = await operation();
      return result;
    } finally {
      if (lock) {
        this.releaseLock(resourceId);
      }
    }
  }

  /**
   * Safe economy transaction with locking
   */
  async safeEconomyTransaction(userId, operation, timeout = 10000) {
    return this.withLock(`economy:${userId}`, operation, timeout);
  }

  /**
   * Safe inventory transaction with locking
   */
  async safeInventoryTransaction(userId, operation, timeout = 10000) {
    return this.withLock(`inventory:${userId}`, operation, timeout);
  }

  /**
   * Safe trading transaction with locking
   */
  async safeTradingTransaction(userId1, userId2, operation, timeout = 15000) {
    // Sort user IDs to prevent deadlock
    const [firstUser, secondUser] = [userId1, userId2].sort();

    return this.withLock(`trading:${firstUser}:${secondUser}`, operation, timeout);
  }

  /**
   * Safe gambling transaction with locking
   */
  async safeGamblingTransaction(userId, operation, timeout = 10000) {
    return this.withLock(`gambling:${userId}`, operation, timeout);
  }

  /**
   * Safe guild transaction with locking
   */
  async safeGuildTransaction(guildId, operation, timeout = 15000) {
    return this.withLock(`guild:${guildId}`, operation, timeout);
  }

  /**
   * Check if resource is locked
   */
  isLocked(resourceId) {
    const lockKey = `lock:${resourceId}`;
    const lock = this.locks.get(lockKey);

    if (!lock) return false;

    const now = Date.now();
    if (now > lock.expiresAt) {
      this.releaseLock(resourceId);
      return false;
    }

    return true;
  }

  /**
   * Get lock information
   */
  getLockInfo(resourceId) {
    const lockKey = `lock:${resourceId}`;
    const lock = this.locks.get(lockKey);

    if (!lock) return null;

    const now = Date.now();
    if (now > lock.expiresAt) {
      this.releaseLock(resourceId);
      return null;
    }

    return {
      resourceId: lock.resourceId,
      acquiredAt: lock.acquiredAt,
      expiresAt: lock.expiresAt,
      remainingTime: lock.expiresAt - now
    };
  }

  /**
   * Get all active locks
   */
  getAllLocks() {
    const activeLocks = [];
    const now = Date.now();

    for (const [lockKey, lock] of this.locks.entries()) {
      if (now <= lock.expiresAt) {
        activeLocks.push({
          resourceId: lock.resourceId,
          acquiredAt: lock.acquiredAt,
          expiresAt: lock.expiresAt,
          remainingTime: lock.expiresAt - now
        });
      } else {
        // Clean up expired lock
        this.releaseLock(lock.resourceId);
      }
    }

    return activeLocks;
  }

  /**
   * Force release all locks (emergency cleanup)
   */
  forceReleaseAllLocks() {
    const lockCount = this.locks.size;

    for (const [lockKey, lock] of this.locks.entries()) {
      clearTimeout(lock.timeoutId);
    }

    this.locks.clear();
    logger.warn(`Force released ${lockCount} locks`);
  }

  /**
   * Clean up expired locks
   */
  cleanupExpiredLocks() {
    const now = Date.now();
    let cleanedCount = 0;

    for (const [lockKey, lock] of this.locks.entries()) {
      if (now > lock.expiresAt) {
        this.releaseLock(lock.resourceId);
        cleanedCount++;
      }
    }

    if (cleanedCount > 0) {
      logger.debug(`Cleaned up ${cleanedCount} expired locks`);
    }
  }

  /**
   * Get statistics
   */
  getStats() {
    this.cleanupExpiredLocks();

    return {
      activeLocks: this.locks.size,
      totalLocks: this.locks.size,
      defaultTimeout: this.defaultTimeout
    };
  }
}

// Create singleton instance
const raceConditionProtection = new RaceConditionProtection();

// Clean up expired locks every minute
setInterval(() => {
  raceConditionProtection.cleanupExpiredLocks();
}, 60000);

module.exports = raceConditionProtection;

/**
 * Replace Insecure Random Number Generation
 * Automatically replaces Math.random() with secure alternatives
 */

const fs = require('fs');
const path = require('path');
const logger = require('../logger');

// Patterns to replace
const REPLACEMENTS = [
  {
    pattern: /Math\.random\(\)/g,
    replacement: 'secureRandomFloat()',
    import: 'const { secureRandomFloat } = require(\'./utils/secureRandom\');'
  },
  {
    pattern: /Math\.floor\(Math\.random\(\) \* (\d+)\)/g,
    replacement: 'secureRandomInt(0, $1)',
    import: 'const { secureRandomInt } = require(\'./utils/secureRandom\');'
  },
  {
    pattern: /Math\.floor\(Math\.random\(\) \* \(([^)]+)\)\)/g,
    replacement: 'secureRandomInt(0, $1)',
    import: 'const { secureRandomInt } = require(\'./utils/secureRandom\');'
  },
  {
    pattern: /Math\.random\(\) < ([^;]+)/g,
    replacement: 'secureRandomBoolean($1)',
    import: 'const { secureRandomBoolean } = require(\'./utils/secureRandom\');'
  }
];

/**
 * Check if file should be processed
 * @param {string} filePath - File path
 * @returns {boolean} Whether to process the file
 */
function shouldProcessFile(filePath) {
  const ext = path.extname(filePath);
  const excludedDirs = ['node_modules', '.git', 'logs', 'docs'];
  const excludedFiles = ['package-lock.json', 'yarn.lock'];

  // Skip non-JavaScript files
  if (!['.js', '.mjs'].includes(ext)) {
    return false;
  }

  // Skip excluded directories
  for (const dir of excludedDirs) {
    if (filePath.includes(dir)) {
      return false;
    }
  }

  // Skip excluded files
  const fileName = path.basename(filePath);
  if (excludedFiles.includes(fileName)) {
    return false;
  }

  return true;
}

/**
 * Process a single file
 * @param {string} filePath - File path
 * @returns {Object} Processing results
 */
function processFile(filePath) {
  try {
    const content = fs.readFileSync(filePath, 'utf8');
    let modified = false;
    let newContent = content;
    const imports = new Set();

    // Apply replacements
    for (const replacement of REPLACEMENTS) {
      if (replacement.pattern.test(newContent)) {
        newContent = newContent.replace(replacement.pattern, replacement.replacement);
        if (replacement.import) {
          imports.add(replacement.import);
        }
        modified = true;
      }
    }

    // Add imports if needed
    if (modified && imports.size > 0) {
      const importLines = Array.from(imports);

      // Find the best place to add imports
      const lines = newContent.split('\n');
      let insertIndex = 0;

      // Look for existing imports
      for (let i = 0; i < lines.length; i++) {
        const line = lines[i].trim();
        if (line.startsWith('const ') && line.includes('require(')) {
          insertIndex = i + 1;
        } else if (line.startsWith('import ') && line.includes('from')) {
          insertIndex = i + 1;
        }
      }

      // Insert new imports
      lines.splice(insertIndex, 0, ...importLines);
      newContent = lines.join('\n');
    }

    // Write file if modified
    if (modified) {
      fs.writeFileSync(filePath, newContent, 'utf8');
      return { filePath, modified: true, imports: Array.from(imports) };
    }

    return { filePath, modified: false };
  } catch (error) {
    logger.error(`Error processing file ${filePath}:`, error);
    return { filePath, modified: false, error: error.message };
  }
}

/**
 * Recursively process directory
 * @param {string} dirPath - Directory path
 * @returns {Array} Processing results
 */
function processDirectory(dirPath) {
  const results = [];

  try {
    const items = fs.readdirSync(dirPath);

    for (const item of items) {
      const fullPath = path.join(dirPath, item);
      const stat = fs.statSync(fullPath);

      if (stat.isDirectory()) {
        results.push(...processDirectory(fullPath));
      } else if (stat.isFile() && shouldProcessFile(fullPath)) {
        results.push(processFile(fullPath));
      }
    }
  } catch (error) {
    logger.error(`Error processing directory ${dirPath}:`, error);
  }

  return results;
}

/**
 * Main function to replace insecure random
 * @param {string} rootPath - Root directory path
 * @returns {Object} Summary of changes
 */
function replaceInsecureRandom(rootPath = '.') {
  logger.info('Starting insecure random replacement...');

  const results = processDirectory(rootPath);
  const modified = results.filter(r => r.modified);
  const errors = results.filter(r => r.error);

  const summary = {
    totalFiles: results.length,
    modifiedFiles: modified.length,
    errors: errors.length,
    modified: modified,
    errors: errors
  };

  logger.info('Insecure random replacement completed:', {
    totalFiles: summary.totalFiles,
    modifiedFiles: summary.modifiedFiles,
    errors: summary.errors
  });

  if (modified.length > 0) {
    logger.info('Modified files:');
    modified.forEach(result => {
      logger.info(`  - ${result.filePath} (added imports: ${result.imports.join(', ')})`);
    });
  }

  if (errors.length > 0) {
    logger.error('Errors encountered:');
    errors.forEach(result => {
      logger.error(`  - ${result.filePath}: ${result.error}`);
    });
  }

  return summary;
}

/**
 * Verify replacements were successful
 * @param {string} rootPath - Root directory path
 * @returns {Object} Verification results
 */
function verifyReplacements(rootPath = '.') {
  logger.info('Verifying replacements...');

  const results = processDirectory(rootPath);
  const filesWithMathRandom = [];

  for (const result of results) {
    if (result.modified) {
      try {
        const content = fs.readFileSync(result.filePath, 'utf8');
        if (content.includes('Math.random()')) {
          filesWithMathRandom.push(result.filePath);
        }
      } catch (error) {
        logger.error(`Error verifying ${result.filePath}:`, error);
      }
    }
  }

  if (filesWithMathRandom.length > 0) {
    logger.warn('Files still contain Math.random():', filesWithMathRandom);
  } else {
    logger.info('All Math.random() calls have been successfully replaced!');
  }

  return {
    filesWithMathRandom,
    allReplaced: filesWithMathRandom.length === 0
  };
}

module.exports = {
  replaceInsecureRandom,
  verifyReplacements,
  processFile,
  processDirectory
};

// Run if called directly
if (require.main === module) {
  const summary = replaceInsecureRandom();
  const verification = verifyReplacements();

  console.log('\n=== SUMMARY ===');
  console.log(`Total files processed: ${summary.totalFiles}`);
  console.log(`Files modified: ${summary.modifiedFiles}`);
  console.log(`Errors: ${summary.errors}`);
  console.log(`All Math.random() replaced: ${verification.allReplaced}`);

  if (!verification.allReplaced) {
    process.exit(1);
  }
}

