/**
 * Validation error class
 */
class ValidationError extends Error {
  constructor(message, field = '', value = null) {
    super(message);
    this.name = 'ValidationError';
    this.field = field;
    this.value = value;
    this.timestamp = new Date().toISOString();
  }
}

/**
 * Core validation functions
 */
const validators = {
  /**
   * Validate Discord user ID
   */
  userId: (value) => {
    if (!value) return false;
    const str = String(value);
    return /^\d{17,19}$/.test(str);
  },

  /**
   * Validate Discord guild ID
   */
  guildId: (value) => {
    if (!value) return false;
    const str = String(value);
    return /^\d{17,19}$/.test(str);
  },

  /**
   * Validate Discord channel ID
   */
  channelId: (value) => {
    if (!value) return false;
    const str = String(value);
    return /^\d{17,19}$/.test(str);
  },

  /**
   * Validate positive integer
   */
  positiveInteger: (value) => {
    const num = parseInt(value);
    return !isNaN(num) && num > 0 && Number.isInteger(num);
  },

  /**
   * Validate non-negative integer
   */
  nonNegativeInteger: (value) => {
    const num = parseInt(value);
    return !isNaN(num) && num >= 0 && Number.isInteger(num);
  },

  /**
   * Validate positive number
   */
  positiveNumber: (value) => {
    const num = parseFloat(value);
    return !isNaN(num) && num > 0;
  },

  /**
   * Validate non-negative number
   */
  nonNegativeNumber: (value) => {
    const num = parseFloat(value);
    return !isNaN(num) && num >= 0;
  },

  /**
   * Validate string length
   */
  stringLength: (value, min = 0, max = Infinity) => {
    if (typeof value !== 'string') return false;
    return value.length >= min && value.length <= max;
  },

  /**
   * Validate email format
   */
  email: (value) => {
    if (!value) return false;
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(String(value));
  },

  /**
   * Validate URL format
   */
  url: (value) => {
    if (!value) return false;
    try {
      new URL(String(value));
      return true;
    } catch {
      return false;
    }
  },

  /**
   * Validate hex color
   */
  hexColor: (value) => {
    if (!value) return false;
    const hexRegex = /^#?([A-Fa-f0-9]{6}|[A-Fa-f0-9]{3})$/;
    return hexRegex.test(String(value));
  },

  /**
   * Validate enum value
   */
  enum: (value, allowedValues) => {
    if (!Array.isArray(allowedValues)) return false;
    return allowedValues.includes(value);
  },

  /**
   * Validate date
   */
  date: (value) => {
    if (!value) return false;
    const date = new Date(value);
    return !isNaN(date.getTime());
  },

  /**
   * Validate future date
   */
  futureDate: (value) => {
    if (!value) return false;
    const date = new Date(value);
    return !isNaN(date.getTime()) && date > new Date();
  },

  /**
   * Validate past date
   */
  pastDate: (value) => {
    if (!value) return false;
    const date = new Date(value);
    return !isNaN(date.getTime()) && date < new Date();
  },

  /**
   * Validate array
   */
  array: (value) => {
    return Array.isArray(value);
  },

  /**
   * Validate object
   */
  object: (value) => {
    return typeof value === 'object' && value !== null && !Array.isArray(value);
  },

  /**
   * Validate boolean
   */
  boolean: (value) => {
    return typeof value === 'boolean';
  },

  /**
   * Validate alphanumeric string
   */
  alphanumeric: (value) => {
    if (!value) return false;
    return /^[a-zA-Z0-9]+$/.test(String(value));
  },

  /**
   * Validate username format
   */
  username: (value) => {
    if (!value) return false;
    const str = String(value);
    return /^[a-zA-Z0-9_]{3,32}$/.test(str);
  },

  /**
   * Validate guild name
   */
  guildName: (value) => {
    if (!value) return false;
    const str = String(value);
    return str.length >= 2 && str.length <= 100;
  },

  /**
   * Validate item name
   */
  itemName: (value) => {
    if (!value) return false;
    const str = String(value);
    return str.length >= 1 && str.length <= 50;
  },

  /**
   * Validate amount for economy operations
   */
  economyAmount: (value) => {
    const num = parseInt(value);
    return !isNaN(num) && num > 0 && num <= 999999999;
  },

  /**
   * Validate percentage (0-100)
   */
  percentage: (value) => {
